{
  "name": "NotebookLM Slide Editor",
  "description": "A professional AI-powered slide editor that converts PDFs to high-res images, allows OCR-based Korean text replacement, and features advanced canvas manipulation tools like zooming and handle-based resizing.",
  "requestFramePermissions": [
    "camera"
  ]
}

export interface Point {
  x: number;
  y: number;
}

export interface Rect {
  x: number;
  y: number;
  width: number;
  height: number;
}

export interface TextOverlay {
  id: string;
  rect: Rect;
  originalText: string;
  newText: string;
  fontSize: number;
  fontWeight: string;
  fontColor: string;
  backgroundColor: string;
}

export interface SlideData {
  index: number;
  dataUrl: string;
  width: number;
  height: number;
  overlays: TextOverlay[];
}

export type HandleType = 'nw' | 'n' | 'ne' | 'e' | 'se' | 's' | 'sw' | 'w';

export interface OCRResult {
  text: string;
  fontSize: number;
  fontWeight: string;
  fontColor: string;
  backgroundColor: string;
}

export const COLORS = {
  primary: '#3b82f6',
  sidebar: '#1e293b',
  canvasBg: '#0f172a',
  overlay: 'rgba(59, 130, 246, 0.2)',
  handle: '#3b82f6',
};

export const HANDLE_SIZE = 8;
export const MIN_RECT_SIZE = 10;
export const ZOOM_STEP = 0.1;
export const MAX_ZOOM = 5;
export const MIN_ZOOM = 0.1;

import { SlideData } from '../types';

declare const pdfjsLib: any;
declare const jspdf: any;

// Use CDN worker for PDF.js
pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';

export const convertPdfToImages = async (file: File): Promise<SlideData[]> => {
  const arrayBuffer = await file.arrayBuffer();
  const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
  const pdf = await loadingTask.promise;
  const slides: SlideData[] = [];

  for (let i = 1; i <= pdf.numPages; i++) {
    const page = await pdf.getPage(i);
    const viewport = page.getViewport({ scale: 2.0 }); // High res
    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d');
    canvas.height = viewport.height;
    canvas.width = viewport.width;

    await page.render({ canvasContext: context, viewport }).promise;

    slides.push({
      index: i - 1,
      dataUrl: canvas.toDataURL('image/png'),
      width: viewport.width,
      height: viewport.height,
      overlays: []
    });
  }

  return slides;
};

export const downloadAsPdf = (slides: SlideData[], filename: string) => {
  const { jsPDF } = jspdf;
  const doc = new jsPDF({
    orientation: slides[0].width > slides[0].height ? 'landscape' : 'portrait',
    unit: 'px',
    format: [slides[0].width, slides[0].height]
  });

  slides.forEach((slide, idx) => {
    if (idx > 0) doc.addPage([slide.width, slide.height]);

    // We need to render the slide with its overlays to a temporary canvas
    const canvas = document.createElement('canvas');
    canvas.width = slide.width;
    canvas.height = slide.height;
    const ctx = canvas.getContext('2d')!;

    const img = new Image();
    img.onload = () => {
      ctx.drawImage(img, 0, 0);

      slide.overlays.forEach(overlay => {
        ctx.fillStyle = overlay.backgroundColor;
        ctx.fillRect(overlay.rect.x, overlay.rect.y, overlay.rect.width, overlay.rect.height);

        ctx.fillStyle = overlay.fontColor;
        ctx.font = `${overlay.fontWeight} ${overlay.fontSize}px sans-serif`;
        ctx.textBaseline = 'top';
        ctx.fillText(overlay.newText, overlay.rect.x, overlay.rect.y);
      });

      const finalDataUrl = canvas.toDataURL('image/jpeg', 0.95);
      doc.addImage(finalDataUrl, 'JPEG', 0, 0, slide.width, slide.height);

      if (idx === slides.length - 1) {
        doc.save(filename);
      }
    };
    img.src = slide.dataUrl;
  });
};

import { GoogleGenAI, Type } from "@google/genai";
import { OCRResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const analyzeTextInImage = async (base64Image: string): Promise<OCRResult> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/png',
            data: base64Image.split(',')[1],
          },
        },
        {
          text: `Identify the Korean text in this image snippet. 
          Estimate the following typography properties:
          1. The exact text content.
          2. Approximate font size in pixels.
          3. Font weight (e.g., normal, bold).
          4. Dominant text color in hex.
          5. Dominant background color in hex behind the text.
          Return ONLY a JSON object with keys: text, fontSize, fontWeight, fontColor, backgroundColor.`
        }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          text: { type: Type.STRING },
          fontSize: { type: Type.NUMBER },
          fontWeight: { type: Type.STRING },
          fontColor: { type: Type.STRING },
          backgroundColor: { type: Type.STRING },
        },
        required: ["text", "fontSize", "fontWeight", "fontColor", "backgroundColor"]
      }
    }
  });

  try {
    const data = JSON.parse(response.text || "{}");
    return {
      text: data.text || "",
      fontSize: data.fontSize || 16,
      fontWeight: data.fontWeight || "normal",
      fontColor: data.fontColor || "#000000",
      backgroundColor: data.backgroundColor || "#ffffff"
    };
  } catch (error) {
    console.error("Failed to parse Gemini response", error);
    return {
      text: "OCR Error",
      fontSize: 16,
      fontWeight: "normal",
      fontColor: "#000000",
      backgroundColor: "#ffffff"
    };
  }
};

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { SlideData, Rect, Point, HandleType, TextOverlay } from '../types';
import { COLORS, HANDLE_SIZE, MIN_RECT_SIZE, ZOOM_STEP, MAX_ZOOM, MIN_ZOOM } from '../constants';

interface EditorCanvasProps {
  slide: SlideData;
  onSelectionChange: (rect: Rect | null) => void;
  onUpdateOverlays: (overlays: TextOverlay[]) => void;
}

const EditorCanvas: React.FC<EditorCanvasProps> = ({ slide, onSelectionChange, onUpdateOverlays }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [zoom, setZoom] = useState(1);
  const [offset, setOffset] = useState<Point>({ x: 0, y: 0 });
  const [selection, setSelection] = useState<Rect | null>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const [dragType, setDragType] = useState<'move' | HandleType | null>(null);
  const [startPoint, setStartPoint] = useState<Point | null>(null);
  const [image, setImage] = useState<HTMLImageElement | null>(null);

  // Load slide image
  useEffect(() => {
    const img = new Image();
    img.src = slide.dataUrl;
    img.onload = () => {
      setImage(img);
      // Auto-scale to fit container
      if (containerRef.current) {
        const { clientWidth, clientHeight } = containerRef.current;
        const scale = Math.min(
          (clientWidth - 40) / img.width,
          (clientHeight - 40) / img.height
        );
        setZoom(scale);
        setOffset({
          x: (clientWidth - img.width * scale) / 2,
          y: (clientHeight - img.height * scale) / 2
        });
      }
    };
  }, [slide.dataUrl]);

  const draw = useCallback(() => {
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (!canvas || !ctx || !image) return;

    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.save();
    ctx.translate(offset.x, offset.y);
    ctx.scale(zoom, zoom);

    // Draw base slide
    ctx.drawImage(image, 0, 0);

    // Draw active overlays
    slide.overlays.forEach(overlay => {
      ctx.fillStyle = overlay.backgroundColor;
      ctx.fillRect(overlay.rect.x, overlay.rect.y, overlay.rect.width, overlay.rect.height);

      ctx.fillStyle = overlay.fontColor;
      ctx.font = `${overlay.fontWeight} ${overlay.fontSize}px sans-serif`;
      ctx.textBaseline = 'top';
      ctx.fillText(overlay.newText, overlay.rect.x, overlay.rect.y);
    });

    // Draw selection
    if (selection) {
      ctx.strokeStyle = COLORS.primary;
      ctx.lineWidth = 2 / zoom;
      ctx.strokeRect(selection.x, selection.y, selection.width, selection.height);
      ctx.fillStyle = COLORS.overlay;
      ctx.fillRect(selection.x, selection.y, selection.width, selection.height);

      // Draw 8 handles
      const handles: Point[] = [
        { x: selection.x, y: selection.y }, // nw
        { x: selection.x + selection.width / 2, y: selection.y }, // n
        { x: selection.x + selection.width, y: selection.y }, // ne
        { x: selection.x + selection.width, y: selection.y + selection.height / 2 }, // e
        { x: selection.x + selection.width, y: selection.y + selection.height }, // se
        { x: selection.x + selection.width / 2, y: selection.y + selection.height }, // s
        { x: selection.x, y: selection.y + selection.height }, // sw
        { x: selection.x, y: selection.y + selection.height / 2 }, // w
      ];

      ctx.fillStyle = COLORS.handle;
      handles.forEach(h => {
        ctx.fillRect(
          h.x - (HANDLE_SIZE / 2) / zoom,
          h.y - (HANDLE_SIZE / 2) / zoom,
          HANDLE_SIZE / zoom,
          HANDLE_SIZE / zoom
        );
      });
    }

    ctx.restore();
  }, [image, slide.overlays, selection, zoom, offset]);

  useEffect(() => {
    draw();
  }, [draw]);

  const getCanvasCoords = (e: React.MouseEvent): Point => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    return {
      x: (e.clientX - rect.left - offset.x) / zoom,
      y: (e.clientY - rect.top - offset.y) / zoom
    };
  };

  const getHandleAt = (p: Point): HandleType | 'move' | null => {
    if (!selection) return null;
    const tolerance = HANDLE_SIZE / zoom;

    const hx = [selection.x, selection.x + selection.width / 2, selection.x + selection.width];
    const hy = [selection.y, selection.y + selection.height / 2, selection.y + selection.height];
    const types: (HandleType | null)[][] = [
      ['nw', 'n', 'ne'],
      ['w', null, 'e'],
      ['sw', 's', 'se']
    ];

    for (let i = 0; i < 3; i++) {
      for (let j = 0; j < 3; j++) {
        const type = types[i][j];
        if (type && Math.abs(p.x - hx[j]) < tolerance && Math.abs(p.y - hy[i]) < tolerance) {
          return type;
        }
      }
    }

    if (p.x >= selection.x && p.x <= selection.x + selection.width &&
        p.y >= selection.y && p.y <= selection.y + selection.height) {
      return 'move';
    }

    return null;
  }

  const handleMouseDown = (e: React.MouseEvent) => {
    const p = getCanvasCoords(e);
    const handle = getHandleAt(p);

    if (handle) {
      setIsDragging(true);
      setDragType(handle);
      setStartPoint(p);
    } else {
      setIsDrawing(true);
      setSelection({ x: p.x, y: p.y, width: 0, height: 0 });
      setStartPoint(p);
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    const p = getCanvasCoords(e);

    if (isDrawing && startPoint) {
      const x = Math.min(p.x, startPoint.x);
      const y = Math.min(p.y, startPoint.y);
      const width = Math.abs(p.x - startPoint.x);
      const height = Math.abs(p.y - startPoint.y);
      setSelection({ x, y, width, height });
    } else if (isDragging && selection && startPoint && dragType) {
      const dx = p.x - startPoint.x;
      const dy = p.y - startPoint.y;
      let newRect = { ...selection };

      if (dragType === 'move') {
        newRect.x += dx;
        newRect.y += dy;
      } else {
        if (dragType.includes('e')) newRect.width += dx;
        if (dragType.includes('w')) {
          newRect.x += dx;
          newRect.width -= dx;
        }
        if (dragType.includes('s')) newRect.height += dy;
        if (dragType.includes('n')) {
          newRect.y += dy;
          newRect.height -= dy;
        }
      }
      setSelection(newRect);
      setStartPoint(p);
    }
  };

  const handleMouseUp = () => {
    setIsDrawing(false);
    setIsDragging(false);
    setDragType(null);
    setStartPoint(null);

    if (selection && (selection.width < MIN_RECT_SIZE || selection.height < MIN_RECT_SIZE)) {
      setSelection(null);
      onSelectionChange(null);
    } else {
      onSelectionChange(selection);
    }
  };

  const handleWheel = (e: React.WheelEvent) => {
    if (e.ctrlKey) {
      e.preventDefault();
      const delta = -e.deltaY;
      const factor = delta > 0 ? (1 + ZOOM_STEP) : (1 - ZOOM_STEP);
      const newZoom = Math.min(MAX_ZOOM, Math.max(MIN_ZOOM, zoom * factor));

      // Zoom relative to mouse
      const rect = canvasRef.current?.getBoundingClientRect();
      if (!rect) return;
      const mouseX = e.clientX - rect.left;
      const mouseY = e.clientY - rect.top;

      const wx = (mouseX - offset.x) / zoom;
      const wy = (mouseY - offset.y) / zoom;

      setZoom(newZoom);
      setOffset({
        x: mouseX - wx * newZoom,
        y: mouseY - wy * newZoom
      });
    } else {
      // Panning
      setOffset(prev => ({
        x: prev.x - e.deltaX,
        y: prev.y - e.deltaY
      }));
    }
  };

  return (
    <div 
      ref={containerRef}
      className="flex-1 relative overflow-hidden bg-[#0f172a] flex items-center justify-center select-none"
      onWheel={handleWheel}
    >
      <canvas
        ref={canvasRef}
        width={containerRef.current?.clientWidth || 800}
        height={containerRef.current?.clientHeight || 600}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
        className="block"
      />

      <div className="absolute top-4 left-1/2 -translate-x-1/2 bg-slate-800/80 px-4 py-2 rounded-full text-xs text-slate-300 border border-slate-700 pointer-events-none flex items-center gap-4">
        <span>Ctrl + 휠: 확대/축소</span>
        <span className="w-px h-3 bg-slate-600"></span>
        <span>드래그: 영역 선택</span>
        <span className="w-px h-3 bg-slate-600"></span>
        <span>핸들: 크기 조절</span>
      </div>
    </div>
  );
};

export default EditorCanvas;

import React, { useState, useEffect } from 'react';
import { Rect, SlideData, TextOverlay, OCRResult } from '../types';
import { analyzeTextInImage } from '../services/geminiService';
import { Loader2, Type as TypeIcon, Info, CheckCircle2 } from 'lucide-react';

interface SidebarProps {
  activeSlide: SlideData;
  selection: Rect | null;
  onApplyOverlay: (overlay: TextOverlay) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ activeSlide, selection, onApplyOverlay }) => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [ocrResult, setOcrResult] = useState<OCRResult | null>(null);
  const [replacementText, setReplacementText] = useState('');
  const [fontSize, setFontSize] = useState(16);
  const [fontWeight, setFontWeight] = useState('normal');

  useEffect(() => {
    if (selection) {
      handleAnalyze();
    } else {
      setOcrResult(null);
      setReplacementText('');
    }
  }, [selection]);

  const handleAnalyze = async () => {
    if (!selection) return;

    setIsAnalyzing(true);
    try {
      // Crop image for OCR
      const canvas = document.createElement('canvas');
      canvas.width = selection.width;
      canvas.height = selection.height;
      const ctx = canvas.getContext('2d');
      const img = new Image();
      img.src = activeSlide.dataUrl;
      await new Promise(resolve => img.onload = resolve);

      ctx?.drawImage(
        img, 
        selection.x, selection.y, selection.width, selection.height, 
        0, 0, selection.width, selection.height
      );

      const cropDataUrl = canvas.toDataURL('image/png');
      const result = await analyzeTextInImage(cropDataUrl);

      setOcrResult(result);
      setReplacementText(result.text);
      setFontSize(result.fontSize);
      setFontWeight(result.fontWeight);
    } catch (err) {
      console.error(err);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleApply = () => {
    if (!selection || !ocrResult) return;

    const overlay: TextOverlay = {
      id: Math.random().toString(36).substr(2, 9),
      rect: { ...selection },
      originalText: ocrResult.text,
      newText: replacementText,
      fontSize: fontSize,
      fontWeight: fontWeight,
      fontColor: ocrResult.fontColor,
      backgroundColor: ocrResult.backgroundColor
    };

    onApplyOverlay(overlay);
  };

  return (
    <div className="w-80 h-full bg-[#1e293b] border-l border-slate-700 flex flex-col p-6 overflow-y-auto">
      <div className="flex items-center gap-2 mb-6">
        <TypeIcon size={20} className="text-blue-400" />
        <h2 className="text-lg font-semibold">한글 텍스트 교체</h2>
      </div>

      {!selection ? (
        <div className="flex-1 flex flex-col items-center justify-center text-center text-slate-400">
          <div className="w-16 h-16 rounded-xl bg-slate-800 flex items-center justify-center mb-4">
            <Info size={32} />
          </div>
          <p className="text-sm">이미지에서 교체할<br/>한글 영역을 드래그하세요</p>
        </div>
      ) : (
        <div className="space-y-6">
          <div className="bg-slate-800/50 rounded-xl p-4 border border-slate-700">
            <h3 className="text-xs font-medium text-slate-400 uppercase tracking-wider mb-3">분석 결과 (OCR)</h3>
            {isAnalyzing ? (
              <div className="flex items-center gap-3 py-4 text-blue-400">
                <Loader2 className="animate-spin" size={18} />
                <span className="text-sm">AI가 분석 중입니다...</span>
              </div>
            ) : ocrResult ? (
              <div className="space-y-3">
                <div className="p-3 bg-slate-900 rounded text-sm text-slate-300 italic">
                  "{ocrResult.text}"
                </div>
                <div className="grid grid-cols-2 gap-2 text-[10px] text-slate-500">
                  <div className="flex flex-col">
                    <span>폰트 크기</span>
                    <span className="text-slate-300 text-xs">{ocrResult.fontSize}px</span>
                  </div>
                  <div className="flex flex-col">
                    <span>두께</span>
                    <span className="text-slate-300 text-xs capitalize">{ocrResult.fontWeight}</span>
                  </div>
                </div>
              </div>
            ) : null}
          </div>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-300 mb-2">교체할 텍스트</label>
              <textarea
                value={replacementText}
                onChange={(e) => setReplacementText(e.target.value)}
                className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-sm focus:ring-2 focus:ring-blue-500 focus:outline-none h-24 resize-none"
                placeholder="새로운 텍스트를 입력하세요..."
              />
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="block text-xs font-medium text-slate-400 mb-1">크기 조절</label>
                <input
                  type="number"
                  value={fontSize}
                  onChange={(e) => setFontSize(Number(e.target.value))}
                  className="w-full bg-slate-900 border border-slate-700 rounded p-2 text-sm"
                />
              </div>
              <div>
                <label className="block text-xs font-medium text-slate-400 mb-1">폰트 스타일</label>
                <select
                  value={fontWeight}
                  onChange={(e) => setFontWeight(e.target.value)}
                  className="w-full bg-slate-900 border border-slate-700 rounded p-2 text-sm"
                >
                  <option value="normal">Normal</option>
                  <option value="bold">Bold</option>
                  <option value="300">Light</option>
                  <option value="600">Semi-Bold</option>
                </select>
              </div>
            </div>

            <button
              onClick={handleApply}
              disabled={isAnalyzing || !ocrResult}
              className="w-full bg-blue-600 hover:bg-blue-500 disabled:opacity-50 disabled:cursor-not-allowed text-white font-medium py-3 rounded-lg transition-colors flex items-center justify-center gap-2 mt-4"
            >
              <CheckCircle2 size={18} />
              텍스트 교체 적용
            </button>
          </div>
        </div>
      )}

      <div className="mt-auto pt-8">
        <div className="bg-blue-500/10 border border-blue-500/20 rounded-lg p-4">
          <h4 className="text-xs font-semibold text-blue-400 flex items-center gap-1.5 mb-2">
            <Info size={12} /> 사용 가이드
          </h4>
          <ul className="text-[11px] text-slate-400 space-y-1.5 list-decimal pl-3">
            <li>교체할 영역을 드래그하여 선택하세요.</li>
            <li>AI가 자동으로 원본 텍스트와 스타일을 분석합니다.</li>
            <li>교체할 텍스트를 입력하고 '적용'을 누르세요.</li>
            <li>편집 내용은 PDF에 즉시 반영됩니다.</li>
          </ul>
        </div>
      </div>
    </div>
  );
};

export default Sidebar;

import React, { useState, useCallback } from 'react';
import { SlideData, Rect, TextOverlay } from './types';
import { convertPdfToImages, downloadAsPdf } from './services/pdfService';
import EditorCanvas from './components/EditorCanvas';
import Sidebar from './components/Sidebar';
import { 
  FileUp, 
  Download, 
  FileText, 
  ChevronLeft, 
  ChevronRight, 
  Trash2, 
  Image as ImageIcon,
  History
} from 'lucide-react';

const App: React.FC = () => {
  const [slides, setSlides] = useState<SlideData[]>([]);
  const [activeSlideIdx, setActiveSlideIdx] = useState(0);
  const [selection, setSelection] = useState<Rect | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    try {
      const converted = await convertPdfToImages(file);
      setSlides(converted);
      setActiveSlideIdx(0);
    } catch (err) {
      console.error(err);
      alert('PDF 변환 중 오류가 발생했습니다.');
    } finally {
      setIsProcessing(false);
    }
  };

  const handleApplyOverlay = (overlay: TextOverlay) => {
    setSlides(prev => prev.map((s, idx) => {
      if (idx === activeSlideIdx) {
        return { ...s, overlays: [...s.overlays, overlay] };
      }
      return s;
    }));
    setSelection(null);
  };

  const handleUndo = () => {
    setSlides(prev => prev.map((s, idx) => {
      if (idx === activeSlideIdx) {
        const newOverlays = [...s.overlays];
        newOverlays.pop();
        return { ...s, overlays: newOverlays };
      }
      return s;
    }));
  };

  const handleDownloadImages = () => {
