  y: number;
  width: number;
  height: number;
}

export interface TextOverlay {
  id: string;
  rect: Rect;
  originalText: string;
  newText: string;
  fontSize: number;
  fontWeight: string;
  fontColor: string;
  backgroundColor: string;
}

export interface GraphicObject {
  id: string;
  rect: Rect;
  dataUrl: string; // 추출된 이미지 조각의 base64
}

export interface SlideData {
  index: number;
