  height: number;
  overlays: TextOverlay[];
  objects: GraphicObject[];
}

export type HandleType = 'nw' | 'n' | 'ne' | 'e' | 'se' | 's' | 'sw' | 'w';

export interface OCRResult {
  text: string;
  fontSize: number;
  fontWeight: string;
  fontColor: string;
  backgroundColor: string;
}

export interface ObjectDetectionResult {
