            </div>
          )}
        </div>
        <Sidebar activeSlide={slides[activeSlideIdx]} selection={selection} selectedObjectId={selectedObjectId} onApplyOverlay={handleApplyOverlay} onExtractObject={handleExtractObject} onDeleteObject={handleDeleteObject} />
      </main>
    </div>
  );
};

export default App;

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { SlideData, Rect, Point, HandleType, TextOverlay, GraphicObject } from '../types';
import { COLORS, HANDLE_SIZE, MIN_RECT_SIZE, ZOOM_STEP, MAX_ZOOM, MIN_ZOOM } from '../constants';

interface EditorCanvasProps {
  slide: SlideData;
  onSelectionChange: (rect: Rect | null, selectedObjectId: string | null) => void;
  onUpdateOverlays: (overlays: TextOverlay[]) => void;
  onUpdateObjects: (objects: GraphicObject[]) => void;
}

const EditorCanvas: React.FC<EditorCanvasProps> = ({ slide, onSelectionChange, onUpdateOverlays, onUpdateObjects }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [zoom, setZoom] = useState(1);
  const [offset, setOffset] = useState<Point>({ x: 0, y: 0 });
  const [selection, setSelection] = useState<Rect | null>(null);
  const [selectedObjectId, setSelectedObjectId] = useState<string | null>(null);

  const [isDrawing, setIsDrawing] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const [dragType, setDragType] = useState<'move' | HandleType | null>(null);
  const [startPoint, setStartPoint] = useState<Point | null>(null);
  const [image, setImage] = useState<HTMLImageElement | null>(null);
  const [objImages, setObjImages] = useState<Record<string, HTMLImageElement>>({});

  // Load slide image
  useEffect(() => {
    const img = new Image();
    img.src = slide.dataUrl;
    img.onload = () => {
      setImage(img);
      if (containerRef.current) {
        const { clientWidth, clientHeight } = containerRef.current;
        const scale = Math.min(
          (clientWidth - 80) / img.width,
          (clientHeight - 80) / img.height
        );
        setZoom(scale);
        setOffset({
          x: (clientWidth - img.width * scale) / 2,
          y: (clientHeight - img.height * scale) / 2
        });
      }
    };
  }, [slide.dataUrl]);

  // Load object images
  useEffect(() => {
    slide.objects.forEach(obj => {
      if (!objImages[obj.id]) {
        const img = new Image();
        img.src = obj.dataUrl;
        img.onload = () => {
          setObjImages(prev => ({ ...prev, [obj.id]: img }));
        };
      }
    });
  }, [slide.objects]);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const handleWheelNative = (e: WheelEvent) => {
      if (e.ctrlKey) {
        e.preventDefault();
        const delta = -e.deltaY;
        const factor = delta > 0 ? (1 + ZOOM_STEP) : (1 - ZOOM_STEP);
        setZoom(prevZoom => {
          const newZoom = Math.min(MAX_ZOOM, Math.max(MIN_ZOOM, prevZoom * factor));
          const rect = canvasRef.current?.getBoundingClientRect();
          if (!rect) return prevZoom;
          const mouseX = e.clientX - rect.left;
          const mouseY = e.clientY - rect.top;
          setOffset(prevOffset => {
            const wx = (mouseX - prevOffset.x) / prevZoom;
            const wy = (mouseY - prevOffset.y) / prevZoom;
            return { x: mouseX - wx * newZoom, y: mouseY - wy * newZoom };
          });
          return newZoom;
        });
      } else {
        setOffset(prev => ({ x: prev.x - e.deltaX, y: prev.y - e.deltaY }));
      }
    };

    container.addEventListener('wheel', handleWheelNative, { passive: false });
    return () => container.removeEventListener('wheel', handleWheelNative);
  }, [zoom]);

  const draw = useCallback(() => {
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (!canvas || !ctx || !image) return;

    const rect = canvas.getBoundingClientRect();
    if (canvas.width !== rect.width || canvas.height !== rect.height) {
      canvas.width = rect.width;
      canvas.height = rect.height;
    }

    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.save();
    ctx.translate(offset.x, offset.y);
    ctx.scale(zoom, zoom);

    // Draw Slide
    ctx.drawImage(image, 0, 0);

    // Draw Objects
    slide.objects.forEach(obj => {
      const objImg = objImages[obj.id];
      if (objImg) {
        ctx.drawImage(objImg, obj.rect.x, obj.rect.y, obj.rect.width, obj.rect.height);
      }
    });

    // Draw Overlays
    slide.overlays.forEach(overlay => {
      ctx.fillStyle = overlay.backgroundColor;
      ctx.fillRect(overlay.rect.x, overlay.rect.y, overlay.rect.width, overlay.rect.height);
      ctx.fillStyle = overlay.fontColor;
      ctx.font = `${overlay.fontWeight} ${overlay.fontSize}px sans-serif`;
      ctx.textBaseline = 'top';
      ctx.fillText(overlay.newText, overlay.rect.x, overlay.rect.y);
    });

    // Draw Active Selection
    if (selection) {
      ctx.strokeStyle = COLORS.primary;
      ctx.lineWidth = 2 / zoom;
      ctx.strokeRect(selection.x, selection.y, selection.width, selection.height);
      ctx.fillStyle = COLORS.overlay;
      ctx.fillRect(selection.x, selection.y, selection.width, selection.height);

      const handles: Point[] = [
        { x: selection.x, y: selection.y },
        { x: selection.x + selection.width / 2, y: selection.y },
        { x: selection.x + selection.width, y: selection.y },
        { x: selection.x + selection.width, y: selection.y + selection.height / 2 },
        { x: selection.x + selection.width, y: selection.y + selection.height },
        { x: selection.x + selection.width / 2, y: selection.y + selection.height },
        { x: selection.x, y: selection.y + selection.height },
        { x: selection.x, y: selection.y + selection.height / 2 },
      ];

      ctx.fillStyle = COLORS.handle;
      handles.forEach(h => {
        ctx.fillRect(h.x - (HANDLE_SIZE / 2) / zoom, h.y - (HANDLE_SIZE / 2) / zoom, HANDLE_SIZE / zoom, HANDLE_SIZE / zoom);
      });
    }

    ctx.restore();
  }, [image, slide.overlays, slide.objects, objImages, selection, zoom, offset]);

  useEffect(() => {
    draw();
  }, [draw]);

  const getCanvasCoords = (e: React.MouseEvent | React.WheelEvent | any): Point => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    return {
      x: (e.clientX - rect.left - offset.x) / zoom,
      y: (e.clientY - rect.top - offset.y) / zoom
    };
  };

  const getHandleAt = (p: Point, rect: Rect): HandleType | 'move' | null => {
    const tolerance = HANDLE_SIZE / zoom;
    const hx = [rect.x, rect.x + rect.width / 2, rect.x + rect.width];
    const hy = [rect.y, rect.y + rect.height / 2, rect.y + rect.height];
    const types: (HandleType | null)[][] = [
      ['nw', 'n', 'ne'],
      ['w', null, 'e'],
      ['sw', 's', 'se']
    ];
    for (let i = 0; i < 3; i++) {
      for (let j = 0; j < 3; j++) {
        const type = types[i][j];
        if (type && Math.abs(p.x - hx[j]) < tolerance && Math.abs(p.y - hy[i]) < tolerance) return type;
      }
    }
    if (p.x >= rect.x && p.x <= rect.x + rect.width && p.y >= rect.y && p.y <= rect.y + rect.height) return 'move';
    return null;
  }

  const handleMouseDown = (e: React.MouseEvent) => {
    const p = getCanvasCoords(e);

    // 1. Check if clicking on an existing object
    for (let i = slide.objects.length - 1; i >= 0; i--) {
      const obj = slide.objects[i];
      const handle = getHandleAt(p, obj.rect);
      if (handle) {
        setSelectedObjectId(obj.id);
        setSelection(obj.rect);
        setIsDragging(true);
        setDragType(handle);
        setStartPoint(p);
        onSelectionChange(obj.rect, obj.id);
        return;
      }
    }

    // 2. Check if clicking on active selection
    if (selection) {
      const handle = getHandleAt(p, selection);
      if (handle) {
        setIsDragging(true);
        setDragType(handle);
        setStartPoint(p);
        return;
      }
    }

    // 3. Start new selection
    setIsDrawing(true);
    setSelection({ x: p.x, y: p.y, width: 0, height: 0 });
    setSelectedObjectId(null);
    setStartPoint(p);
    onSelectionChange(null, null);
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    const p = getCanvasCoords(e);

    // Cursor handling
    let foundObject = false;
    for (let i = slide.objects.length - 1; i >= 0; i--) {
      const obj = slide.objects[i];
      if (getHandleAt(p, obj.rect)) {
        foundObject = true;
        break;
      }
    }

    if (canvasRef.current) {
      if (isDragging || isDrawing) {
        canvasRef.current.style.cursor = 'grabbing';
      } else if (foundObject) {
        canvasRef.current.style.cursor = 'pointer';
      } else if (selection && getHandleAt(p, selection)) {
        canvasRef.current.style.cursor = 'move';
      } else {
        canvasRef.current.style.cursor = 'crosshair';
      }
    }

    if (isDrawing && startPoint) {
      const x = Math.min(p.x, startPoint.x);
      const y = Math.min(p.y, startPoint.y);
      const width = Math.abs(p.x - startPoint.x);
      const height = Math.abs(p.y - startPoint.y);
      setSelection({ x, y, width, height });
    } else if (isDragging && selection && startPoint && dragType) {
      const dx = p.x - startPoint.x;
      const dy = p.y - startPoint.y;
      let newRect = { ...selection };
      if (dragType === 'move') {
        newRect.x += dx;
        newRect.y += dy;
      } else {
        if (dragType.includes('e')) newRect.width += dx;
        if (dragType.includes('w')) { newRect.x += dx; newRect.width -= dx; }
        if (dragType.includes('s')) newRect.height += dy;
        if (dragType.includes('n')) { newRect.y += dy; newRect.height -= dy; }
      }
      setSelection(newRect);
      if (selectedObjectId) {
        onUpdateObjects(slide.objects.map(o => o.id === selectedObjectId ? { ...o, rect: newRect } : o));
      }
      setStartPoint(p);
    }
  };

  const handleMouseUp = () => {
    setIsDrawing(false);
    setIsDragging(false);
    setDragType(null);
    setStartPoint(null);
    if (selection && (selection.width < MIN_RECT_SIZE || selection.height < MIN_RECT_SIZE)) {
      setSelection(null);
      onSelectionChange(null, null);
    } else {
      onSelectionChange(selection, selectedObjectId);
    }
  };

  return (
    <div ref={containerRef} className="flex-1 relative overflow-hidden bg-[#0f172a] flex items-center justify-center select-none">
      <canvas ref={canvasRef} onMouseDown={handleMouseDown} onMouseMove={handleMouseMove} onMouseUp={handleMouseUp} onMouseLeave={handleMouseUp} className="block w-full h-full" />
      <div className="absolute top-4 left-1/2 -translate-x-1/2 bg-slate-800/90 px-5 py-2.5 rounded-full text-xs font-medium text-slate-200 border border-slate-700 shadow-2xl pointer-events-none flex items-center gap-5 backdrop-blur-sm">
        <div className="flex items-center gap-2">
          <span className="bg-slate-700 px-1.5 py-0.5 rounded text-[10px] text-blue-400 font-bold">Ctrl + Wheel</span>
          <span>확대/축소</span>
        </div>
        <div className="w-px h-3 bg-slate-600"></div>
        <div className="flex items-center gap-2">
          <span className="bg-slate-700 px-1.5 py-0.5 rounded text-[10px] text-blue-400 font-bold">Drag</span>
          <span>영역/객체 선택</span>
        </div>
      </div>
      <div className="absolute bottom-4 right-4 bg-slate-900/80 px-3 py-1.5 rounded-lg border border-slate-700 text-[10px] font-mono text-slate-400">
        ZOOM: {(zoom * 100).toFixed(0)}%
      </div>
    </div>
  );
};

export default EditorCanvas;

import React, { useState, useEffect } from 'react';
import { Rect, SlideData, TextOverlay, OCRResult, GraphicObject } from '../types';
import { analyzeTextInImage, detectObjectInImage } from '../services/geminiService';
import { Loader2, Type as TypeIcon, Info, CheckCircle2, Scissors, Trash2, LayoutGrid } from 'lucide-react';

interface SidebarProps {
  activeSlide: SlideData;
  selection: Rect | null;
  selectedObjectId: string | null;
  onApplyOverlay: (overlay: TextOverlay) => void;
  onExtractObject: (obj: GraphicObject, newSlideImageData: string) => void;
  onDeleteObject: (id: string) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ activeSlide, selection, selectedObjectId, onApplyOverlay, onExtractObject, onDeleteObject }) => {
  const [mode, setMode] = useState<'text' | 'graphic'>('text');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [ocrResult, setOcrResult] = useState<OCRResult | null>(null);
  const [replacementText, setReplacementText] = useState('');
  const [fontSize, setFontSize] = useState(16);
  const [fontWeight, setFontWeight] = useState('normal');

  useEffect(() => {
    if (selection && !selectedObjectId) {
      if (mode === 'text') handleAnalyze();
    } else if (!selection) {
      setOcrResult(null);
      setReplacementText('');
    }
  }, [selection, mode, selectedObjectId]);

  const handleAnalyze = async () => {
    if (!selection) return;
    setIsAnalyzing(true);
    try {
      const canvas = document.createElement('canvas');
      canvas.width = selection.width;
      canvas.height = selection.height;
      const ctx = canvas.getContext('2d');
      const img = new Image();
      img.src = activeSlide.dataUrl;
      await new Promise(resolve => img.onload = resolve);
      ctx?.drawImage(img, selection.x, selection.y, selection.width, selection.height, 0, 0, selection.width, selection.height);
      const cropDataUrl = canvas.toDataURL('image/png');
      const result = await analyzeTextInImage(cropDataUrl);
      setOcrResult(result);
      setReplacementText(result.text);
      setFontSize(result.fontSize);
      setFontWeight(result.fontWeight);
    } catch (err) {
      console.error(err);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleExtractGraphic = async () => {
    if (!selection) return;
    setIsAnalyzing(true);
    try {
      const canvas = document.createElement('canvas');
      canvas.width = selection.width;
      canvas.height = selection.height;
      const ctx = canvas.getContext('2d');
      const img = new Image();
      img.src = activeSlide.dataUrl;
      await new Promise(resolve => img.onload = resolve);

      // AI refinement of bounding box
      ctx?.drawImage(img, selection.x, selection.y, selection.width, selection.height, 0, 0, selection.width, selection.height);
      const cropDataUrl = canvas.toDataURL('image/png');
      const refinedBox = await detectObjectInImage(cropDataUrl);

      let finalRect = { ...selection };
      if (refinedBox) {
        finalRect = {
          x: selection.x + refinedBox.x * selection.width,
          y: selection.y + refinedBox.y * selection.height,
          width: refinedBox.w * selection.width,
          height: refinedBox.h * selection.height
        };
      }

      // 1. 객체 이미지 추출 (PNG)
      const finalCanvas = document.createElement('canvas');
      finalCanvas.width = finalRect.width;
      finalCanvas.height = finalRect.height;
      const finalCtx = finalCanvas.getContext('2d');
      finalCtx?.drawImage(img, finalRect.x, finalRect.y, finalRect.width, finalRect.height, 0, 0, finalRect.width, finalRect.height);
      const extractedPng = finalCanvas.toDataURL('image/png');

      // 2. 원본 이미지에서 객체 자리 지우기 (배경색으로 채움)
      // 간단한 인페인팅: 선택 영역 테두리 픽셀 색상의 평균값을 구함
      const sampleCanvas = document.createElement('canvas');
      sampleCanvas.width = img.width;
      sampleCanvas.height = img.height;
      const sampleCtx = sampleCanvas.getContext('2d')!;
      sampleCtx.drawImage(img, 0, 0);

      // 추출 영역의 좌상단 1픽셀을 샘플링하여 배경색으로 가정 (일반적인 슬라이드 배경)
      const pixel = sampleCtx.getImageData(finalRect.x > 0 ? finalRect.x - 1 : 0, finalRect.y > 0 ? finalRect.y - 1 : 0, 1, 1).data;
      const bgColor = `rgb(${pixel[0]}, ${pixel[1]}, ${pixel[2]})`;

      sampleCtx.fillStyle = bgColor;
      sampleCtx.fillRect(finalRect.x, finalRect.y, finalRect.width, finalRect.height);
      const newSlideImageData = sampleCanvas.toDataURL('image/png');

      onExtractObject({
        id: Math.random().toString(36).substr(2, 9),
        rect: finalRect,
        dataUrl: extractedPng
      }, newSlideImageData);

    } catch (err) {
      console.error(err);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleApply = () => {
    if (!selection || !ocrResult) return;
    onApplyOverlay({
      id: Math.random().toString(36).substr(2, 9),
      rect: { ...selection },
      originalText: ocrResult.text,
      newText: replacementText,
      fontSize,
      fontWeight,
      fontColor: ocrResult.fontColor,
      backgroundColor: ocrResult.backgroundColor
    });
  };

  return (
    <div className="w-80 h-full bg-[#1e293b] border-l border-slate-700 flex flex-col p-6 overflow-y-auto">
      <div className="flex p-1 bg-slate-900 rounded-lg mb-6">
        <button onClick={() => setMode('text')} className={`flex-1 py-2 text-xs font-bold rounded-md transition-all ${mode === 'text' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-slate-200'}`}>텍스트 편집</button>
        <button onClick={() => setMode('graphic')} className={`flex-1 py-2 text-xs font-bold rounded-md transition-all ${mode === 'graphic' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-slate-200'}`}>객체 추출</button>
      </div>

      {!selection && !selectedObjectId ? (
        <div className="flex-1 flex flex-col items-center justify-center text-center text-slate-400">
          <div className="w-16 h-16 rounded-xl bg-slate-800 flex items-center justify-center mb-4">
            <Info size={32} />
          </div>
          <p className="text-sm">이미지에서 작업할<br/>영역을 선택하세요</p>

          {activeSlide.objects.length > 0 && (
            <div className="mt-8 w-full">
              <div className="flex items-center gap-2 mb-3 text-slate-500">
                <LayoutGrid size={14} />
                <span className="text-[10px] uppercase tracking-wider font-bold">추출된 객체 리스트</span>
              </div>
              <div className="grid grid-cols-2 gap-2">
                {activeSlide.objects.map(obj => (
                  <div key={obj.id} className="aspect-square bg-slate-900 border border-slate-700 rounded-lg p-2 flex items-center justify-center overflow-hidden group relative">
                    <img src={obj.dataUrl} alt="extracted" className="max-w-full max-h-full object-contain" />
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      ) : selectedObjectId ? (
        <div className="space-y-6">
          <div className="bg-slate-800 rounded-xl p-4 border border-blue-500/30 text-center">
             <div className="w-full aspect-video bg-slate-900 rounded-lg mb-4 flex items-center justify-center p-4 border border-slate-700">
                <img src={activeSlide.objects.find(o => o.id === selectedObjectId)?.dataUrl} className="max-w-full max-h-full object-contain" />
             </div>
            <h3 className="text-sm font-bold text-blue-400 mb-4 tracking-tight">선택된 객체 관리</h3>
            <button onClick={() => onDeleteObject(selectedObjectId)} className="w-full flex items-center justify-center gap-2 py-3 bg-red-900/30 hover:bg-red-900/50 text-red-400 border border-red-500/30 rounded-lg transition-all">
              <Trash2 size={18} /> 객체 삭제
            </button>
          </div>
        </div>
      ) : mode === 'text' ? (
        <div className="space-y-6">
          <div className="bg-slate-800/50 rounded-xl p-4 border border-slate-700">
            <h3 className="text-xs font-medium text-slate-400 uppercase tracking-wider mb-3">분석 결과 (OCR)</h3>
            {isAnalyzing ? (
              <div className="flex items-center gap-3 py-4 text-blue-400">
                <Loader2 className="animate-spin" size={18} />
                <span className="text-sm">AI가 분석 중입니다...</span>
              </div>
            ) : ocrResult ? (
              <div className="space-y-3">
                <div className="p-3 bg-slate-900 rounded text-sm text-slate-300 italic">"{ocrResult.text}"</div>
              </div>
            ) : null}
          </div>
          <div className="space-y-4">
            <textarea value={replacementText} onChange={(e) => setReplacementText(e.target.value)} className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-sm h-24 resize-none" placeholder="새 텍스트 입력..." />
            <button onClick={handleApply} disabled={isAnalyzing || !ocrResult} className="w-full bg-blue-600 hover:bg-blue-500 disabled:opacity-50 text-white font-medium py-3 rounded-lg flex items-center justify-center gap-2"><CheckCircle2 size={18} /> 텍스트 적용</button>
          </div>
        </div>
      ) : (
        <div className="space-y-6 text-center">
          <div className="w-20 h-20 mx-auto rounded-full bg-blue-600/10 flex items-center justify-center text-blue-400 mb-4 border border-blue-500/20">
            <Scissors size={32} />
          </div>
          <h3 className="text-lg font-bold">도형/이미지 추출</h3>
          <p className="text-xs text-slate-400">선택한 영역을 PNG 객체로 추출하고,<br/>원본 자리는 배경으로 채웁니다.</p>
          <button onClick={handleExtractGraphic} disabled={isAnalyzing} className="w-full bg-blue-600 hover:bg-blue-500 disabled:opacity-50 text-white font-medium py-4 rounded-lg flex items-center justify-center gap-2 mt-4">
            {isAnalyzing ? <Loader2 className="animate-spin" size={18} /> : <Scissors size={18} />}
            선택 영역 추출 & 삭제
          </button>
        </div>
      )}
    </div>
  );
};

export default Sidebar;

import React, { useState, useCallback, useEffect } from 'react';
import { SlideData, Rect, TextOverlay, GraphicObject } from './types';
import { convertPdfToImages, downloadAsPdf } from './services/pdfService';
import EditorCanvas from './components/EditorCanvas';
import Sidebar from './components/Sidebar';
import { 
  FileUp, 
  Download, 
  FileText, 
  ChevronLeft, 
  ChevronRight, 
  Trash2, 
  Image as ImageIcon,
  History
} from 'lucide-react';

const App: React.FC = () => {
  const [slides, setSlides] = useState<SlideData[]>([]);
  const [activeSlideIdx, setActiveSlideIdx] = useState(0);
  const [selection, setSelection] = useState<Rect | null>(null);
  const [selectedObjectId, setSelectedObjectId] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedObjectId) {
        handleDeleteObject(selectedObjectId);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedObjectId]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessing(true);
    try {
      const converted = await convertPdfToImages(file);
      setSlides(converted);
      setActiveSlideIdx(0);
    } catch (err) {
      console.error(err);
      alert('PDF 변환 중 오류가 발생했습니다.');
    } finally {
      setIsProcessing(false);
    }
  };

  const handleApplyOverlay = (overlay: TextOverlay) => {
    setSlides(prev => prev.map((s, idx) => idx === activeSlideIdx ? { ...s, overlays: [...s.overlays, overlay] } : s));
    setSelection(null);
  };

  const handleExtractObject = (obj: GraphicObject, newSlideImageData: string) => {
    setSlides(prev => prev.map((s, idx) => idx === activeSlideIdx ? { 
      ...s, 
      dataUrl: newSlideImageData, // 원본 슬라이드에서 객체 영역이 지워진 새 데이터
      objects: [...s.objects, obj] 
    } : s));
    setSelection(null);
  };

  const handleDeleteObject = (id: string) => {
    setSlides(prev => prev.map((s, idx) => idx === activeSlideIdx ? { ...s, objects: s.objects.filter(o => o.id !== id) } : s));
    setSelectedObjectId(null);
    setSelection(null);
  };

  const handleUpdateObjects = (objects: GraphicObject[]) => {
    setSlides(prev => prev.map((s, idx) => idx === activeSlideIdx ? { ...s, objects } : s));
  };

  const handleUndo = () => {
    setSlides(prev => prev.map((s, idx) => {
      if (idx === activeSlideIdx) {
        if (s.overlays.length > 0) {
          const newOverlays = [...s.overlays];
          newOverlays.pop();
          return { ...s, overlays: newOverlays };
        } else if (s.objects.length > 0) {
          const newObjects = [...s.objects];
          newObjects.pop();
          return { ...s, objects: newObjects };
        }
      }
      return s;
    }));
  };

  const handleDownloadImages = () => {
    slides.forEach((slide, i) => {
      const canvas = document.createElement('canvas');
      canvas.width = slide.width;
      canvas.height = slide.height;
      const ctx = canvas.getContext('2d')!;
      const img = new Image();
      img.src = slide.dataUrl;
      img.onload = () => {
        ctx.drawImage(img, 0, 0);

        // Render Objects
        slide.objects.forEach(obj => {
          const oImg = new Image();
          oImg.src = obj.dataUrl;
          oImg.onload = () => {
            ctx.drawImage(oImg, obj.rect.x, obj.rect.y, obj.rect.width, obj.rect.height);
          };
        });

        // Render Overlays
        slide.overlays.forEach(ov => {
          ctx.fillStyle = ov.backgroundColor;
          ctx.fillRect(ov.rect.x, ov.rect.y, ov.rect.width, ov.rect.height);
          ctx.fillStyle = ov.fontColor;
          ctx.font = `${ov.fontWeight} ${ov.fontSize}px sans-serif`;
          ctx.textBaseline = 'top';
          ctx.fillText(ov.newText, ov.rect.x, ov.rect.y);
        });

        setTimeout(() => {
          const link = document.createElement('a');
          link.href = canvas.toDataURL('image/png');
          link.download = `edited_slide_${i + 1}.png`;
          link.click();
        }, 100);
      };
    });
  };

  const handleDownloadPdf = () => {
    if (slides.length === 0) return;
    downloadAsPdf(slides, 'edited_slides.pdf');
  };

  return (
    <div className="flex flex-col h-screen bg-[#0f172a] text-slate-100 font-sans">
      <header className="h-16 border-b border-slate-800 flex items-center justify-between px-6 bg-[#1e293b] shrink-0">
        <div className="flex items-center gap-4">
          <div className="bg-blue-600 p-2 rounded-lg"><FileText size={20} /></div>
          <div>
            <h1 className="text-lg font-bold">NotebookLM Slide Editor</h1>
            <p className="text-[10px] text-slate-400 uppercase tracking-widest">AI Graphics Engine</p>
          </div>
        </div>
        <div className="flex items-center gap-3">
          <label className="flex items-center gap-2 px-4 py-2 bg-slate-700 hover:bg-slate-600 rounded-lg cursor-pointer transition-colors text-sm font-medium">
            <FileUp size={18} /><span>PDF 업로드</span>
            <input type="file" accept=".pdf" className="hidden" onChange={handleFileUpload} />
          </label>
          <div className="w-px h-6 bg-slate-700 mx-2"></div>
          <button onClick={handleDownloadImages} disabled={slides.length === 0} className="flex items-center gap-2 px-4 py-2 bg-slate-800 hover:bg-slate-700 disabled:opacity-50 text-slate-300 rounded-lg text-sm border border-slate-700">
            <Download size={18} /><span>이미지 일괄 저장</span>
          </button>
          <button onClick={handleDownloadPdf} disabled={slides.length === 0} className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-500 disabled:opacity-50 text-white rounded-lg text-sm font-bold transition-all shadow-lg shadow-blue-900/20">
            <FileText size={18} /><span>PDF에 반영 (p.{activeSlideIdx + 1})</span>
          </button>
        </div>
      </header>
      <main className="flex flex-1 overflow-hidden">
        <aside className="w-20 border-r border-slate-800 bg-[#1e293b] flex flex-col items-center py-6 gap-6 shrink-0">
          <button className="p-3 rounded-xl bg-blue-600/10 text-blue-400 border border-blue-600/20"><ImageIcon size={24} /></button>
          <button onClick={handleUndo} className="p-3 rounded-xl hover:bg-slate-700 text-slate-400 transition-colors"><History size={24} /></button>
          <button onClick={() => setSlides(prev => prev.map((s, idx) => idx === activeSlideIdx ? {...s, overlays: [], objects: []} : s))} className="p-3 rounded-xl hover:bg-red-900/20 hover:text-red-400 text-slate-400 transition-colors"><Trash2 size={24} /></button>
        </aside>
        <div className="flex-1 flex flex-col bg-slate-950">
          {isProcessing ? (
            <div className="flex-1 flex flex-col items-center justify-center gap-4">
              <div className="w-12 h-12 border-4 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
              <p className="text-slate-400 font-medium">PDF를 고해상도 이미지로 변환 중입니다...</p>
            </div>
          ) : slides.length > 0 ? (
            <>
              <EditorCanvas slide={slides[activeSlideIdx]} onSelectionChange={(rect, id) => { setSelection(rect); setSelectedObjectId(id); }} onUpdateOverlays={(overlays) => setSlides(prev => prev.map((s, i) => i === activeSlideIdx ? { ...s, overlays } : s))} onUpdateObjects={handleUpdateObjects} />
              <div className="h-12 bg-[#1e293b] border-t border-slate-800 flex items-center justify-center gap-8 shrink-0">
                <button disabled={activeSlideIdx === 0} onClick={() => setActiveSlideIdx(prev => prev - 1)} className="p-1 hover:bg-slate-700 rounded disabled:opacity-20"><ChevronLeft /></button>
                <span className="text-sm font-medium text-slate-400">SLIDE <span className="text-white">{activeSlideIdx + 1}</span> / {slides.length}</span>
                <button disabled={activeSlideIdx === slides.length - 1} onClick={() => setActiveSlideIdx(prev => prev + 1)} className="p-1 hover:bg-slate-700 rounded disabled:opacity-20"><ChevronRight /></button>
              </div>
            </>
          ) : (
            <div className="flex-1 flex flex-col items-center justify-center text-slate-500 p-8 text-center">
              <div className="w-32 h-32 mb-8 bg-slate-900 rounded-3xl flex items-center justify-center border-2 border-dashed border-slate-800"><FileUp size={48} className="opacity-20" /></div>
              <h3 className="text-xl font-bold text-slate-300 mb-2">편집할 PDF를 불러오세요</h3>
              <label className="mt-8 px-8 py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-full font-bold cursor-pointer transition-all shadow-xl shadow-blue-600/20">시작하기<input type="file" accept=".pdf" className="hidden" onChange={handleFileUpload} /></label>
            </div>
          )}
        </div>
        <Sidebar activeSlide={slides[activeSlideIdx]} selection={selection} selectedObjectId={selectedObjectId} onApplyOverlay={handleApplyOverlay} onExtractObject={handleExtractObject} onDeleteObject={handleDeleteObject} />
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Rect, SlideData, TextOverlay, OCRResult, GraphicObject } from '../types';
import { analyzeTextInImage, detectObjectInImage } from '../services/geminiService';
import { Loader2, Type as TypeIcon, Info, CheckCircle2, Scissors, Trash2, LayoutGrid } from 'lucide-react';

interface SidebarProps {
  activeSlide: SlideData | undefined;
  selection: Rect | null;
  selectedObjectId: string | null;
  onApplyOverlay: (overlay: TextOverlay) => void;
  onExtractObject: (obj: GraphicObject, newSlideImageData: string) => void;
  onDeleteObject: (id: string) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ activeSlide, selection, selectedObjectId, onApplyOverlay, onExtractObject, onDeleteObject }) => {
  const [mode, setMode] = useState<'text' | 'graphic'>('text');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [ocrResult, setOcrResult] = useState<OCRResult | null>(null);
  const [replacementText, setReplacementText] = useState('');
  const [fontSize, setFontSize] = useState(16);
  const [fontWeight, setFontWeight] = useState('normal');

  useEffect(() => {
    if (selection && !selectedObjectId) {
      if (mode === 'text') handleAnalyze();
    } else if (!selection) {
      setOcrResult(null);
      setReplacementText('');
    }
  }, [selection, mode, selectedObjectId]);

  const handleAnalyze = async () => {
    if (!selection || !activeSlide) return;
    setIsAnalyzing(true);
    try {
      const canvas = document.createElement('canvas');
      canvas.width = selection.width;
      canvas.height = selection.height;
      const ctx = canvas.getContext('2d');
      const img = new Image();
      img.src = activeSlide.dataUrl;
      await new Promise(resolve => img.onload = resolve);
      ctx?.drawImage(img, selection.x, selection.y, selection.width, selection.height, 0, 0, selection.width, selection.height);
      const cropDataUrl = canvas.toDataURL('image/png');
      const result = await analyzeTextInImage(cropDataUrl);
      setOcrResult(result);
      setReplacementText(result.text);
      setFontSize(result.fontSize);
      setFontWeight(result.fontWeight);
    } catch (err) {
      console.error(err);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleExtractGraphic = async () => {
    if (!selection || !activeSlide) return;
    setIsAnalyzing(true);
    try {
      const canvas = document.createElement('canvas');
      canvas.width = selection.width;
      canvas.height = selection.height;
      const ctx = canvas.getContext('2d');
      const img = new Image();
      img.src = activeSlide.dataUrl;
      await new Promise(resolve => img.onload = resolve);

      // AI refinement of bounding box
      ctx?.drawImage(img, selection.x, selection.y, selection.width, selection.height, 0, 0, selection.width, selection.height);
      const cropDataUrl = canvas.toDataURL('image/png');
      const refinedBox = await detectObjectInImage(cropDataUrl);

      let finalRect = { ...selection };
      if (refinedBox) {
        finalRect = {
          x: selection.x + refinedBox.x * selection.width,
          y: selection.y + refinedBox.y * selection.height,
          width: refinedBox.w * selection.width,
          height: refinedBox.h * selection.height
        };
      }

      // 1. 객체 이미지 추출 (PNG)
      const finalCanvas = document.createElement('canvas');
      finalCanvas.width = finalRect.width;
      finalCanvas.height = finalRect.height;
      const finalCtx = finalCanvas.getContext('2d');
      finalCtx?.drawImage(img, finalRect.x, finalRect.y, finalRect.width, finalRect.height, 0, 0, finalRect.width, finalRect.height);
      const extractedPng = finalCanvas.toDataURL('image/png');

      // 2. 원본 이미지에서 객체 자리 지우기 (배경색으로 채움)
      const sampleCanvas = document.createElement('canvas');
      sampleCanvas.width = img.width;
      sampleCanvas.height = img.height;
      const sampleCtx = sampleCanvas.getContext('2d')!;
      sampleCtx.drawImage(img, 0, 0);

      const pixel = sampleCtx.getImageData(
        Math.max(0, Math.floor(finalRect.x > 0 ? finalRect.x - 1 : 0)), 
        Math.max(0, Math.floor(finalRect.y > 0 ? finalRect.y - 1 : 0)), 
        1, 1
      ).data;
      const bgColor = `rgb(${pixel[0]}, ${pixel[1]}, ${pixel[2]})`;

      sampleCtx.fillStyle = bgColor;
      sampleCtx.fillRect(finalRect.x, finalRect.y, finalRect.width, finalRect.height);
      const newSlideImageData = sampleCanvas.toDataURL('image/png');

      onExtractObject({
        id: Math.random().toString(36).substr(2, 9),
        rect: finalRect,
        dataUrl: extractedPng
      }, newSlideImageData);

    } catch (err) {
      console.error(err);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleApply = () => {
    if (!selection || !ocrResult) return;
    onApplyOverlay({
      id: Math.random().toString(36).substr(2, 9),
      rect: { ...selection },
      originalText: ocrResult.text,
      newText: replacementText,
      fontSize,
      fontWeight,
      fontColor: ocrResult.fontColor,
      backgroundColor: ocrResult.backgroundColor
    });
  };

  return (
    <div className="w-80 h-full bg-[#1e293b] border-l border-slate-700 flex flex-col p-6 overflow-y-auto">
      <div className="flex p-1 bg-slate-900 rounded-lg mb-6">
        <button onClick={() => setMode('text')} className={`flex-1 py-2 text-xs font-bold rounded-md transition-all ${mode === 'text' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-slate-200'}`}>텍스트 편집</button>
        <button onClick={() => setMode('graphic')} className={`flex-1 py-2 text-xs font-bold rounded-md transition-all ${mode === 'graphic' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-slate-200'}`}>객체 추출</button>
      </div>

      {!selection && !selectedObjectId ? (
        <div className="flex-1 flex flex-col items-center justify-center text-center text-slate-400">
          <div className="w-16 h-16 rounded-xl bg-slate-800 flex items-center justify-center mb-4">
            <Info size={32} />
          </div>
          <p className="text-sm">이미지에서 작업할<br/>영역을 선택하세요</p>

          {activeSlide?.objects && activeSlide.objects.length > 0 && (
            <div className="mt-8 w-full text-left">
              <div className="flex items-center gap-2 mb-3 text-slate-500">
                <LayoutGrid size={14} />
                <span className="text-[10px] uppercase tracking-wider font-bold">추출된 객체 리스트</span>
              </div>
              <div className="grid grid-cols-2 gap-2">
                {activeSlide.objects.map(obj => (
                  <div key={obj.id} className="aspect-square bg-slate-900 border border-slate-700 rounded-lg p-2 flex items-center justify-center overflow-hidden group relative">
                    <img src={obj.dataUrl} alt="extracted" className="max-w-full max-h-full object-contain" />
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      ) : selectedObjectId ? (
        <div className="space-y-6">
          <div className="bg-slate-800 rounded-xl p-4 border border-blue-500/30 text-center">
             <div className="w-full aspect-video bg-slate-900 rounded-lg mb-4 flex items-center justify-center p-4 border border-slate-700">
                <img src={activeSlide?.objects?.find(o => o.id === selectedObjectId)?.dataUrl} className="max-w-full max-h-full object-contain" />
             </div>
            <h3 className="text-sm font-bold text-blue-400 mb-4 tracking-tight">선택된 객체 관리</h3>
            <button onClick={() => onDeleteObject(selectedObjectId)} className="w-full flex items-center justify-center gap-2 py-3 bg-red-900/30 hover:bg-red-900/50 text-red-400 border border-red-500/30 rounded-lg transition-all">
              <Trash2 size={18} /> 객체 삭제
            </button>
          </div>
        </div>
      ) : mode === 'text' ? (
        <div className="space-y-6">
          <div className="bg-slate-800/50 rounded-xl p-4 border border-slate-700">
            <h3 className="text-xs font-medium text-slate-400 uppercase tracking-wider mb-3">분석 결과 (OCR)</h3>
            {isAnalyzing ? (
              <div className="flex items-center gap-3 py-4 text-blue-400">
                <Loader2 className="animate-spin" size={18} />
                <span className="text-sm">AI가 분석 중입니다...</span>
              </div>
            ) : ocrResult ? (
              <div className="space-y-3">
                <div className="p-3 bg-slate-900 rounded text-sm text-slate-300 italic">"{ocrResult.text}"</div>
              </div>
            ) : null}
          </div>
          <div className="space-y-4">
            <textarea value={replacementText} onChange={(e) => setReplacementText(e.target.value)} className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-sm h-24 resize-none" placeholder="새 텍스트 입력..." />
            <button onClick={handleApply} disabled={isAnalyzing || !ocrResult} className="w-full bg-blue-600 hover:bg-blue-500 disabled:opacity-50 text-white font-medium py-3 rounded-lg flex items-center justify-center gap-2"><CheckCircle2 size={18} /> 텍스트 적용</button>
          </div>
        </div>
      ) : (
        <div className="space-y-6 text-center">
          <div className="w-20 h-20 mx-auto rounded-full bg-blue-600/10 flex items-center justify-center text-blue-400 mb-4 border border-blue-500/20">
            <Scissors size={32} />
          </div>
          <h3 className="text-lg font-bold">도형/이미지 추출</h3>
          <p className="text-xs text-slate-400">선택한 영역을 PNG 객체로 추출하고,<br/>원본 자리는 배경으로 채웁니다.</p>
          <button onClick={handleExtractGraphic} disabled={isAnalyzing} className="w-full bg-blue-600 hover:bg-blue-500 disabled:opacity-50 text-white font-medium py-4 rounded-lg flex items-center justify-center gap-2 mt-4">
            {isAnalyzing ? <Loader2 className="animate-spin" size={18} /> : <Scissors size={18} />}
            선택 영역 추출 & 삭제
          </button>
        </div>
      )}
    </div>
  );
};

export default Sidebar;

export interface Point {
  x: number;
  y: number;
}

export interface Rect {
  x: number;
  y: number;
  width: number;
  height: number;
}

export interface TextOverlay {
  id: string;
  rect: Rect;
  originalText: string;
  newText: string;
  fontSize: number;
  fontWeight: string;
  fontColor: string;
  backgroundColor: string;
}

export interface SlideData {
  index: number;
  dataUrl: string;
  width: number;
  height: number;
  overlays: TextOverlay[];
}

export type HandleType = 'nw' | 'n' | 'ne' | 'e' | 'se' | 's' | 'sw' | 'w';

export interface OCRResult {
  text: string;
  fontSize: number;
  fontWeight: string;
  fontColor: string;
  backgroundColor: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { OCRResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const analyzeTextInImage = async (base64Image: string): Promise<OCRResult> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/png',
            data: base64Image.split(',')[1],
          },
        },
        {
          text: `Identify the Korean text in this image snippet. 
          Estimate the following typography properties:
          1. The exact text content.
          2. Approximate font size in pixels.
          3. Font weight (e.g., normal, bold).
          4. Dominant text color in hex.
          5. Dominant background color in hex behind the text.
          Return ONLY a JSON object with keys: text, fontSize, fontWeight, fontColor, backgroundColor.`
        }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          text: { type: Type.STRING },
          fontSize: { type: Type.NUMBER },
          fontWeight: { type: Type.STRING },
          fontColor: { type: Type.STRING },
          backgroundColor: { type: Type.STRING },
        },
        required: ["text", "fontSize", "fontWeight", "fontColor", "backgroundColor"]
      }
    }
  });

  try {
    const data = JSON.parse(response.text || "{}");
    return {
      text: data.text || "",
      fontSize: data.fontSize || 16,
      fontWeight: data.fontWeight || "normal",
      fontColor: data.fontColor || "#000000",
      backgroundColor: data.backgroundColor || "#ffffff"
    };
  } catch (error) {
    console.error("Failed to parse Gemini response", error);
    return {
      text: "OCR Error",
      fontSize: 16,
      fontWeight: "normal",
      fontColor: "#000000",
      backgroundColor: "#ffffff"
    };
  }
};

import { SlideData } from '../types';

declare const pdfjsLib: any;
declare const jspdf: any;

// Use CDN worker for PDF.js
pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';

export const convertPdfToImages = async (file: File): Promise<SlideData[]> => {
  const arrayBuffer = await file.arrayBuffer();
  const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
  const pdf = await loadingTask.promise;
  const slides: SlideData[] = [];

  for (let i = 1; i <= pdf.numPages; i++) {
    const page = await pdf.getPage(i);
    const viewport = page.getViewport({ scale: 2.0 }); // High res
    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d');
    canvas.height = viewport.height;
    canvas.width = viewport.width;

    await page.render({ canvasContext: context, viewport }).promise;

    slides.push({
      index: i - 1,
      dataUrl: canvas.toDataURL('image/png'),
      width: viewport.width,
      height: viewport.height,
      overlays: []
    });
  }

  return slides;
};

export const downloadAsPdf = (slides: SlideData[], filename: string) => {
  const { jsPDF } = jspdf;
  const doc = new jsPDF({
    orientation: slides[0].width > slides[0].height ? 'landscape' : 'portrait',
    unit: 'px',
    format: [slides[0].width, slides[0].height]
  });

  const processSlide = async (slide: SlideData, idx: number) => {
    if (idx > 0) doc.addPage([slide.width, slide.height]);

    const canvas = document.createElement('canvas');
    canvas.width = slide.width;
    canvas.height = slide.height;
    const ctx = canvas.getContext('2d')!;

    const img = new Image();
    img.src = slide.dataUrl;
    await new Promise(resolve => img.onload = resolve);

    ctx.drawImage(img, 0, 0);

    // Draw Text Overlays
    slide.overlays.forEach(overlay => {
      ctx.fillStyle = overlay.backgroundColor;
      ctx.fillRect(overlay.rect.x, overlay.rect.y, overlay.rect.width, overlay.rect.height);

      ctx.fillStyle = overlay.fontColor;
      ctx.font = `${overlay.fontWeight} ${overlay.fontSize}px sans-serif`;
      ctx.textBaseline = 'top';
      ctx.fillText(overlay.newText, overlay.rect.x, overlay.rect.y);
    });

    const finalDataUrl = canvas.toDataURL('image/jpeg', 0.95);
    doc.addImage(finalDataUrl, 'JPEG', 0, 0, slide.width, slide.height);
  };

  const saveAll = async () => {
    for (let i = 0; i < slides.length; i++) {
      await processSlide(slides[i], i);
    }
    doc.save(filename);
  };

  saveAll();
};

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { SlideData, Rect, Point, HandleType, TextOverlay } from '../types';
import { COLORS, HANDLE_SIZE, MIN_RECT_SIZE, ZOOM_STEP, MAX_ZOOM, MIN_ZOOM } from '../constants';

interface EditorCanvasProps {
  slide: SlideData;
  onSelectionChange: (rect: Rect | null) => void;
  onUpdateOverlays: (overlays: TextOverlay[]) => void;
}

const EditorCanvas: React.FC<EditorCanvasProps> = ({ slide, onSelectionChange, onUpdateOverlays }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [zoom, setZoom] = useState(1);
  const [offset, setOffset] = useState<Point>({ x: 0, y: 0 });
  const [selection, setSelection] = useState<Rect | null>(null);

  const [isDrawing, setIsDrawing] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const [dragType, setDragType] = useState<'move' | HandleType | null>(null);
  const [startPoint, setStartPoint] = useState<Point | null>(null);
  const [image, setImage] = useState<HTMLImageElement | null>(null);

  // Load slide image
  useEffect(() => {
    const img = new Image();
    img.src = slide.dataUrl;
    img.onload = () => {
      setImage(img);
      if (containerRef.current) {
        const { clientWidth, clientHeight } = containerRef.current;
        const scale = Math.min(
          (clientWidth - 80) / img.width,
          (clientHeight - 80) / img.height
        );
        setZoom(scale);
        setOffset({
          x: (clientWidth - img.width * scale) / 2,
          y: (clientHeight - img.height * scale) / 2
        });
      }
    };
  }, [slide.dataUrl]);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const handleWheelNative = (e: WheelEvent) => {
      if (e.ctrlKey) {
        e.preventDefault();
        const delta = -e.deltaY;
        const factor = delta > 0 ? (1 + ZOOM_STEP) : (1 - ZOOM_STEP);
        setZoom(prevZoom => {
          const newZoom = Math.min(MAX_ZOOM, Math.max(MIN_ZOOM, prevZoom * factor));
          const rect = canvasRef.current?.getBoundingClientRect();
          if (!rect) return prevZoom;
          const mouseX = e.clientX - rect.left;
          const mouseY = e.clientY - rect.top;
          setOffset(prevOffset => {
            const wx = (mouseX - prevOffset.x) / prevZoom;
            const wy = (mouseY - prevOffset.y) / prevZoom;
            return { x: mouseX - wx * newZoom, y: mouseY - wy * newZoom };
          });
          return newZoom;
        });
      } else {
        setOffset(prev => ({ x: prev.x - e.deltaX, y: prev.y - e.deltaY }));
      }
    };

    container.addEventListener('wheel', handleWheelNative, { passive: false });
    return () => container.removeEventListener('wheel', handleWheelNative);
  }, [zoom]);

  const draw = useCallback(() => {
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (!canvas || !ctx || !image) return;

    const rect = canvas.getBoundingClientRect();
    if (canvas.width !== rect.width || canvas.height !== rect.height) {
      canvas.width = rect.width;
      canvas.height = rect.height;
    }

    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.save();
    ctx.translate(offset.x, offset.y);
    ctx.scale(zoom, zoom);

    // Draw Slide
    ctx.drawImage(image, 0, 0);

    // Draw Overlays
    slide.overlays.forEach(overlay => {
      ctx.fillStyle = overlay.backgroundColor;
      ctx.fillRect(overlay.rect.x, overlay.rect.y, overlay.rect.width, overlay.rect.height);
      ctx.fillStyle = overlay.fontColor;
      ctx.font = `${overlay.fontWeight} ${overlay.fontSize}px sans-serif`;
      ctx.textBaseline = 'top';
      ctx.fillText(overlay.newText, overlay.rect.x, overlay.rect.y);
    });

    // Draw Active Selection
    if (selection) {
      ctx.strokeStyle = COLORS.primary;
      ctx.lineWidth = 2 / zoom;
      ctx.strokeRect(selection.x, selection.y, selection.width, selection.height);
      ctx.fillStyle = COLORS.overlay;
      ctx.fillRect(selection.x, selection.y, selection.width, selection.height);

      const handles: Point[] = [
        { x: selection.x, y: selection.y },
        { x: selection.x + selection.width / 2, y: selection.y },
        { x: selection.x + selection.width, y: selection.y },
        { x: selection.x + selection.width, y: selection.y + selection.height / 2 },
        { x: selection.x + selection.width, y: selection.y + selection.height },
        { x: selection.x + selection.width / 2, y: selection.y + selection.height },
        { x: selection.x, y: selection.y + selection.height },
        { x: selection.x, y: selection.y + selection.height / 2 },
      ];

      ctx.fillStyle = COLORS.handle;
      handles.forEach(h => {
        ctx.fillRect(h.x - (HANDLE_SIZE / 2) / zoom, h.y - (HANDLE_SIZE / 2) / zoom, HANDLE_SIZE / zoom, HANDLE_SIZE / zoom);
      });
    }

    ctx.restore();
  }, [image, slide.overlays, selection, zoom, offset]);

  useEffect(() => {
    draw();
  }, [draw]);

  const getCanvasCoords = (e: React.MouseEvent | React.WheelEvent | any): Point => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    return {
      x: (e.clientX - rect.left - offset.x) / zoom,
      y: (e.clientY - rect.top - offset.y) / zoom
    };
  };

  const getHandleAt = (p: Point, rect: Rect): HandleType | 'move' | null => {
    const tolerance = HANDLE_SIZE / zoom;
    const hx = [rect.x, rect.x + rect.width / 2, rect.x + rect.width];
    const hy = [rect.y, rect.y + rect.height / 2, rect.y + rect.height];
    const types: (HandleType | null)[][] = [
      ['nw', 'n', 'ne'],
      ['w', null, 'e'],
      ['sw', 's', 'se']
    ];
    for (let i = 0; i < 3; i++) {
      for (let j = 0; j < 3; j++) {
        const type = types[i][j];
        if (type && Math.abs(p.x - hx[j]) < tolerance && Math.abs(p.y - hy[i]) < tolerance) return type;
      }
    }
    if (p.x >= rect.x && p.x <= rect.x + rect.width && p.y >= rect.y && p.y <= rect.y + rect.height) return 'move';
    return null;
  }

  const handleMouseDown = (e: React.MouseEvent) => {
    const p = getCanvasCoords(e);

    // 1. Check if clicking on active selection
    if (selection) {
      const handle = getHandleAt(p, selection);
      if (handle) {
        setIsDragging(true);
        setDragType(handle);
        setStartPoint(p);
        return;
      }
    }

    // 2. Start new selection
    setIsDrawing(true);
    setSelection({ x: p.x, y: p.y, width: 0, height: 0 });
    setStartPoint(p);
    onSelectionChange(null);
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    const p = getCanvasCoords(e);

    if (canvasRef.current) {
      if (isDragging || isDrawing) {
        canvasRef.current.style.cursor = 'grabbing';
      } else if (selection && getHandleAt(p, selection)) {
        canvasRef.current.style.cursor = 'move';
      } else {
        canvasRef.current.style.cursor = 'crosshair';
      }
    }

    if (isDrawing && startPoint) {
      const x = Math.min(p.x, startPoint.x);
      const y = Math.min(p.y, startPoint.y);
      const width = Math.abs(p.x - startPoint.x);
      const height = Math.abs(p.y - startPoint.y);
      setSelection({ x, y, width, height });
    } else if (isDragging && selection && startPoint && dragType) {
      const dx = p.x - startPoint.x;
      const dy = p.y - startPoint.y;
      let newRect = { ...selection };
      if (dragType === 'move') {
        newRect.x += dx;
        newRect.y += dy;
      } else {
        if (dragType.includes('e')) newRect.width += dx;
        if (dragType.includes('w')) { newRect.x += dx; newRect.width -= dx; }
        if (dragType.includes('s')) newRect.height += dy;
        if (dragType.includes('n')) { newRect.y += dy; newRect.height -= dy; }
      }
      setSelection(newRect);
      setStartPoint(p);
    }
  };

  const handleMouseUp = () => {
    setIsDrawing(false);
    setIsDragging(false);
    setDragType(null);
    setStartPoint(null);
    if (selection && (selection.width < MIN_RECT_SIZE || selection.height < MIN_RECT_SIZE)) {
      setSelection(null);
      onSelectionChange(null);
    } else {
      onSelectionChange(selection);
    }
  };

  return (
    <div ref={containerRef} className="flex-1 relative overflow-hidden bg-[#0f172a] flex items-center justify-center select-none">
      <canvas ref={canvasRef} onMouseDown={handleMouseDown} onMouseMove={handleMouseMove} onMouseUp={handleMouseUp} onMouseLeave={handleMouseUp} className="block w-full h-full" />
      <div className="absolute top-4 left-1/2 -translate-x-1/2 bg-slate-800/90 px-5 py-2.5 rounded-full text-xs font-medium text-slate-200 border border-slate-700 shadow-2xl pointer-events-none flex items-center gap-5 backdrop-blur-sm">
        <div className="flex items-center gap-2">
          <span className="bg-slate-700 px-1.5 py-0.5 rounded text-[10px] text-blue-400 font-bold">Ctrl + Wheel</span>
          <span>확대/축소</span>
        </div>
        <div className="w-px h-3 bg-slate-600"></div>
        <div className="flex items-center gap-2">
          <span className="bg-slate-700 px-1.5 py-0.5 rounded text-[10px] text-blue-400 font-bold">Drag</span>
          <span>영역 선택</span>
        </div>
      </div>
      <div className="absolute bottom-4 right-4 bg-slate-900/80 px-3 py-1.5 rounded-lg border border-slate-700 text-[10px] font-mono text-slate-400">
        ZOOM: {(zoom * 100).toFixed(0)}%
      </div>
    </div>
  );
};

export default EditorCanvas;

import React, { useState, useEffect } from 'react';
import { Rect, SlideData, TextOverlay, OCRResult } from '../types';
import { analyzeTextInImage } from '../services/geminiService';
import { Loader2, Type as TypeIcon, Info, CheckCircle2 } from 'lucide-react';

interface SidebarProps {
  activeSlide: SlideData | undefined;
  selection: Rect | null;
  onApplyOverlay: (overlay: TextOverlay) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ activeSlide, selection, onApplyOverlay }) => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [ocrResult, setOcrResult] = useState<OCRResult | null>(null);
  const [replacementText, setReplacementText] = useState('');
  const [fontSize, setFontSize] = useState(16);
  const [fontWeight, setFontWeight] = useState('normal');

  useEffect(() => {
    if (selection) {
      handleAnalyze();
    } else {
      setOcrResult(null);
      setReplacementText('');
    }
  }, [selection]);

  const handleAnalyze = async () => {
    if (!selection || !activeSlide) return;
    setIsAnalyzing(true);
    try {
      const canvas = document.createElement('canvas');
      canvas.width = selection.width;
      canvas.height = selection.height;
      const ctx = canvas.getContext('2d');
      const img = new Image();
      img.src = activeSlide.dataUrl;
      await new Promise(resolve => img.onload = resolve);
      ctx?.drawImage(img, selection.x, selection.y, selection.width, selection.height, 0, 0, selection.width, selection.height);
      const cropDataUrl = canvas.toDataURL('image/png');
      const result = await analyzeTextInImage(cropDataUrl);
      setOcrResult(result);
      setReplacementText(result.text);
      setFontSize(result.fontSize);
      setFontWeight(result.fontWeight);
    } catch (err) {
      console.error(err);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleApply = () => {
    if (!selection || !ocrResult) return;
    onApplyOverlay({
      id: Math.random().toString(36).substr(2, 9),
      rect: { ...selection },
      originalText: ocrResult.text,
      newText: replacementText,
      fontSize,
      fontWeight,
      fontColor: ocrResult.fontColor,
      backgroundColor: ocrResult.backgroundColor
    });
  };

  return (
    <div className="w-80 h-full bg-[#1e293b] border-l border-slate-700 flex flex-col p-6 overflow-y-auto">
      <div className="mb-6">
        <h2 className="text-sm font-bold text-slate-200 flex items-center gap-2">
          <TypeIcon size={16} className="text-blue-400" />
          텍스트 편집
        </h2>
      </div>

      {!selection ? (
        <div className="flex-1 flex flex-col items-center justify-center text-center text-slate-400">
          <div className="w-16 h-16 rounded-xl bg-slate-800 flex items-center justify-center mb-4">
            <Info size={32} />
          </div>
          <p className="text-sm">텍스트를 교체할<br/>영역을 선택하세요</p>
        </div>
      ) : (
        <div className="space-y-6">
          <div className="bg-slate-800/50 rounded-xl p-4 border border-slate-700">
            <h3 className="text-xs font-medium text-slate-400 uppercase tracking-wider mb-3">분석 결과 (OCR)</h3>
            {isAnalyzing ? (
              <div className="flex items-center gap-3 py-4 text-blue-400">
                <Loader2 className="animate-spin" size={18} />
                <span className="text-sm">AI가 분석 중입니다...</span>
              </div>
            ) : ocrResult ? (
              <div className="space-y-3">
                <div className="p-3 bg-slate-900 rounded text-sm text-slate-300 italic">"{ocrResult.text}"</div>
              </div>
            ) : null}
          </div>
          <div className="space-y-4">
            <label className="block text-xs font-medium text-slate-500 uppercase">교체할 텍스트</label>
            <textarea 
              value={replacementText} 
              onChange={(e) => setReplacementText(e.target.value)} 
              className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-sm h-32 resize-none focus:outline-none focus:border-blue-500 transition-colors" 
              placeholder="새 텍스트 입력..." 
            />
            <button 
              onClick={handleApply} 
              disabled={isAnalyzing || !ocrResult} 
              className="w-full bg-blue-600 hover:bg-blue-500 disabled:opacity-50 text-white font-medium py-3 rounded-lg flex items-center justify-center gap-2 transition-all"
            >
              <CheckCircle2 size={18} /> 텍스트 적용
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default Sidebar;

import React, { useState, useEffect } from 'react';
import { SlideData, Rect, TextOverlay } from './types';
import { convertPdfToImages, downloadAsPdf } from './services/pdfService';
import EditorCanvas from './components/EditorCanvas';
import Sidebar from './components/Sidebar';
import { 
  FileUp, 
  Download, 
  FileText, 
  ChevronLeft, 
  ChevronRight, 
  Trash2, 
  History
} from 'lucide-react';

const App: React.FC = () => {
  const [slides, setSlides] = useState<SlideData[]>([]);
  const [activeSlideIdx, setActiveSlideIdx] = useState(0);
  const [selection, setSelection] = useState<Rect | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessing(true);
    try {
      const converted = await convertPdfToImages(file);
      setSlides(converted);
      setActiveSlideIdx(0);
    } catch (err) {
      console.error(err);
      alert('PDF 변환 중 오류가 발생했습니다.');
    } finally {
      setIsProcessing(false);
    }
  };

  const handleApplyOverlay = (overlay: TextOverlay) => {
    setSlides(prev => prev.map((s, idx) => idx === activeSlideIdx ? { ...s, overlays: [...s.overlays, overlay] } : s));
    setSelection(null);
  };

  const handleUndo = () => {
    setSlides(prev => prev.map((s, idx) => {
      if (idx === activeSlideIdx && s.overlays.length > 0) {
        const newOverlays = [...s.overlays];
        newOverlays.pop();
        return { ...s, overlays: newOverlays };
      }
      return s;
    }));
  };

  const handleDownloadImages = () => {
    slides.forEach((slide, i) => {
      const canvas = document.createElement('canvas');
      canvas.width = slide.width;
      canvas.height = slide.height;
      const ctx = canvas.getContext('2d')!;
      const img = new Image();
      img.src = slide.dataUrl;
      img.onload = () => {
        ctx.drawImage(img, 0, 0);

        // Render Overlays
        slide.overlays.forEach(ov => {
          ctx.fillStyle = ov.backgroundColor;
          ctx.fillRect(ov.rect.x, ov.rect.y, ov.rect.width, ov.rect.height);
          ctx.fillStyle = ov.fontColor;
          ctx.font = `${ov.fontWeight} ${ov.fontSize}px sans-serif`;
          ctx.textBaseline = 'top';
          ctx.fillText(ov.newText, ov.rect.x, ov.rect.y);
        });

        setTimeout(() => {
          const link = document.createElement('a');
          link.href = canvas.toDataURL('image/png');
          link.download = `edited_slide_${i + 1}.png`;
          link.click();
        }, 100);
      };
    });
  };

  const handleDownloadPdf = () => {
    if (slides.length === 0) return;
    downloadAsPdf(slides, 'edited_slides.pdf');
  };

  return (
    <div className="flex flex-col h-screen bg-[#0f172a] text-slate-100 font-sans">
      <header className="h-16 border-b border-slate-800 flex items-center justify-between px-6 bg-[#1e293b] shrink-0">
        <div className="flex items-center gap-4">
          <div className="bg-blue-600 p-2 rounded-lg"><FileText size={20} /></div>
          <div>
            <h1 className="text-lg font-bold">NotebookLM Slide Editor</h1>
            <p className="text-[10px] text-slate-400 uppercase tracking-widest">AI Slide Engine</p>
          </div>
        </div>
        <div className="flex items-center gap-3">
          <label className="flex items-center gap-2 px-4 py-2 bg-slate-700 hover:bg-slate-600 rounded-lg cursor-pointer transition-colors text-sm font-medium">
            <FileUp size={18} /><span>PDF 업로드</span>
            <input type="file" accept=".pdf" className="hidden" onChange={handleFileUpload} />
          </label>
          <div className="w-px h-6 bg-slate-700 mx-2"></div>
          <button onClick={handleDownloadImages} disabled={slides.length === 0} className="flex items-center gap-2 px-4 py-2 bg-slate-800 hover:bg-slate-700 disabled:opacity-50 text-slate-300 rounded-lg text-sm border border-slate-700">
            <Download size={18} /><span>이미지 일괄 저장</span>
          </button>
          <button onClick={handleDownloadPdf} disabled={slides.length === 0} className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-500 disabled:opacity-50 text-white rounded-lg text-sm font-bold transition-all shadow-lg shadow-blue-900/20">
            <FileText size={18} /><span>PDF 다운로드</span>
          </button>
        </div>
      </header>
      <main className="flex flex-1 overflow-hidden">
        <aside className="w-20 border-r border-slate-800 bg-[#1e293b] flex flex-col items-center py-6 gap-6 shrink-0">
          <button onClick={handleUndo} className="p-3 rounded-xl hover:bg-slate-700 text-slate-400 transition-colors" title="실행 취소">
            <History size={24} />
          </button>
          <button onClick={() => setSlides(prev => prev.map((s, idx) => idx === activeSlideIdx ? {...s, overlays: []} : s))} className="p-3 rounded-xl hover:bg-red-900/20 hover:text-red-400 text-slate-400 transition-colors" title="전체 삭제">
            <Trash2 size={24} />
          </button>
        </aside>
        <div className="flex-1 flex flex-col bg-slate-950">
          {isProcessing ? (
            <div className="flex-1 flex flex-col items-center justify-center gap-4">
              <div className="w-12 h-12 border-4 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
              <p className="text-slate-400 font-medium">PDF를 이미지로 변환 중입니다...</p>
            </div>
          ) : slides.length > 0 ? (
            <>
              <EditorCanvas 
                slide={slides[activeSlideIdx]} 
                onSelectionChange={setSelection} 
                onUpdateOverlays={(overlays) => setSlides(prev => prev.map((s, i) => i === activeSlideIdx ? { ...s, overlays } : s))} 
              />
              <div className="h-12 bg-[#1e293b] border-t border-slate-800 flex items-center justify-center gap-8 shrink-0">
                <button disabled={activeSlideIdx === 0} onClick={() => setActiveSlideIdx(prev => prev - 1)} className="p-1 hover:bg-slate-700 rounded disabled:opacity-20"><ChevronLeft /></button>
                <span className="text-sm font-medium text-slate-400">SLIDE <span className="text-white">{activeSlideIdx + 1}</span> / {slides.length}</span>
                <button disabled={activeSlideIdx === slides.length - 1} onClick={() => setActiveSlideIdx(prev => prev + 1)} className="p-1 hover:bg-slate-700 rounded disabled:opacity-20"><ChevronRight /></button>
              </div>
            </>
          ) : (
            <div className="flex-1 flex flex-col items-center justify-center text-slate-500 p-8 text-center">
              <div className="w-32 h-32 mb-8 bg-slate-900 rounded-3xl flex items-center justify-center border-2 border-dashed border-slate-800"><FileUp size={48} className="opacity-20" /></div>
              <h3 className="text-xl font-bold text-slate-300 mb-2">편집할 PDF를 불러오세요</h3>
              <label className="mt-8 px-8 py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-full font-bold cursor-pointer transition-all shadow-xl shadow-blue-600/20">시작하기<input type="file" accept=".pdf" className="hidden" onChange={handleFileUpload} /></label>
            </div>
          )}
        </div>
        <Sidebar 
          activeSlide={slides[activeSlideIdx]} 
          selection={selection} 
          onApplyOverlay={handleApplyOverlay} 
        />
      </main>
    </div>
  );
};

