import React, { useRef, useEffect, useState, useCallback } from 'react';
import { SlideData, Rect, Point, HandleType, TextOverlay } from '../types';
import { COLORS, HANDLE_SIZE, MIN_RECT_SIZE, ZOOM_STEP, MAX_ZOOM, MIN_ZOOM } from '../constants';

interface EditorCanvasProps {
  slide: SlideData;
  selectedOverlayId: string | null;
  onSelectionChange: (rect: Rect | null) => void;
  onOverlaySelect: (id: string | null) => void;
  onUpdateOverlays: (overlays: TextOverlay[]) => void;
}

const EditorCanvas: React.FC<EditorCanvasProps> = ({ 
  slide, 
  selectedOverlayId,
  onSelectionChange, 
  onOverlaySelect,
  onUpdateOverlays 
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [zoom, setZoom] = useState(1);
  const [offset, setOffset] = useState<Point>({ x: 0, y: 0 });
  const [selection, setSelection] = useState<Rect | null>(null);

  const [isDrawing, setIsDrawing] = useState(false);
  const [isDraggingOverlay, setIsDraggingOverlay] = useState(false);
  const [dragType, setDragType] = useState<'move' | HandleType | null>(null);
  const [startPoint, setStartPoint] = useState<Point | null>(null);
  const [image, setImage] = useState<HTMLImageElement | null>(null);

  // Load slide image
  useEffect(() => {
    const img = new Image();
    img.src = slide.dataUrl;
    img.onload = () => {
      setImage(img);
      if (containerRef.current) {
        const { clientWidth, clientHeight } = containerRef.current;
        const scale = Math.min(
          (clientWidth - 80) / img.width,
          (clientHeight - 80) / img.height
        );
        setZoom(scale);
        setOffset({
          x: (clientWidth - img.width * scale) / 2,
          y: (clientHeight - img.height * scale) / 2
        });
      }
    };
  }, [slide.dataUrl]);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const handleWheelNative = (e: WheelEvent) => {
      if (e.ctrlKey) {
        e.preventDefault();
        const delta = -e.deltaY;
        const factor = delta > 0 ? (1 + ZOOM_STEP) : (1 - ZOOM_STEP);
        setZoom(prevZoom => {
          const newZoom = Math.min(MAX_ZOOM, Math.max(MIN_ZOOM, prevZoom * factor));
          const rect = canvasRef.current?.getBoundingClientRect();
          if (!rect) return prevZoom;
          const mouseX = e.clientX - rect.left;
          const mouseY = e.clientY - rect.top;
          setOffset(prevOffset => {
            const wx = (mouseX - prevOffset.x) / prevZoom;
            const wy = (mouseY - prevOffset.y) / prevZoom;
            return { x: mouseX - wx * newZoom, y: mouseY - wy * newZoom };
          });
          return newZoom;
        });
      } else {
        setOffset(prev => ({ x: prev.x - e.deltaX, y: prev.y - e.deltaY }));
      }
    };

    container.addEventListener('wheel', handleWheelNative, { passive: false });
    return () => container.removeEventListener('wheel', handleWheelNative);
  }, [zoom]);

  const draw = useCallback(() => {
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (!canvas || !ctx || !image) return;

    const rect = canvas.getBoundingClientRect();
    if (canvas.width !== rect.width || canvas.height !== rect.height) {
      canvas.width = rect.width;
      canvas.height = rect.height;
    }

    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.save();
    ctx.translate(offset.x, offset.y);
    ctx.scale(zoom, zoom);

    // Draw Slide
    ctx.drawImage(image, 0, 0);

    // Draw Overlays
    slide.overlays.forEach(overlay => {
      // Background mask
      ctx.fillStyle = overlay.backgroundColor;
      ctx.fillRect(overlay.rect.x, overlay.rect.y, overlay.rect.width, overlay.rect.height);

      // Highlight if selected
      if (overlay.id === selectedOverlayId) {
        ctx.strokeStyle = COLORS.primary;
        ctx.lineWidth = 2 / zoom;
        ctx.strokeRect(overlay.rect.x, overlay.rect.y, overlay.rect.width, overlay.rect.height);
      }

      // Text
      ctx.fillStyle = overlay.fontColor;
      ctx.font = `${overlay.fontWeight} ${overlay.fontSize}px sans-serif`;
      ctx.textBaseline = 'top';
      ctx.fillText(overlay.newText, overlay.rect.x, overlay.rect.y);
    });

    // Draw Area Selection (for OCR)
    if (selection) {
      ctx.strokeStyle = COLORS.primary;
      ctx.lineWidth = 2 / zoom;
      ctx.strokeRect(selection.x, selection.y, selection.width, selection.height);
      ctx.fillStyle = COLORS.overlay;
      ctx.fillRect(selection.x, selection.y, selection.width, selection.height);

      const handles: Point[] = [
        { x: selection.x, y: selection.y },
        { x: selection.x + selection.width / 2, y: selection.y },
        { x: selection.x + selection.width, y: selection.y },
        { x: selection.x + selection.width, y: selection.y + selection.height / 2 },
        { x: selection.x + selection.width, y: selection.y + selection.height },
        { x: selection.x + selection.width / 2, y: selection.y + selection.height },
        { x: selection.x, y: selection.y + selection.height },
        { x: selection.x, y: selection.y + selection.height / 2 },
      ];

      ctx.fillStyle = COLORS.handle;
      handles.forEach(h => {
        ctx.fillRect(h.x - (HANDLE_SIZE / 2) / zoom, h.y - (HANDLE_SIZE / 2) / zoom, HANDLE_SIZE / zoom, HANDLE_SIZE / zoom);
      });
    }

    ctx.restore();
  }, [image, slide.overlays, selection, zoom, offset, selectedOverlayId]);

  useEffect(() => {
    draw();
  }, [draw]);

  const getCanvasCoords = (e: React.MouseEvent | React.WheelEvent | any): Point => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    return {
      x: (e.clientX - rect.left - offset.x) / zoom,
      y: (e.clientY - rect.top - offset.y) / zoom
    };
  };

  const isPointInRect = (p: Point, rect: Rect) => {
    return p.x >= rect.x && p.x <= rect.x + rect.width && p.y >= rect.y && p.y <= rect.y + rect.height;
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    const p = getCanvasCoords(e);

    // Check if clicked on an existing overlay
    const clickedOverlay = [...slide.overlays].reverse().find(o => isPointInRect(p, o.rect));

    if (clickedOverlay) {
      onOverlaySelect(clickedOverlay.id);
      setIsDraggingOverlay(true);
      setStartPoint(p);
      setSelection(null);
      onSelectionChange(null);
      return;
    }

    // New selection start
    onOverlaySelect(null);
    setIsDrawing(true);
    setSelection({ x: p.x, y: p.y, width: 0, height: 0 });
    setStartPoint(p);
    onSelectionChange(null);
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    const p = getCanvasCoords(e);

    // Cursor logic
    const overOverlay = slide.overlays.some(o => isPointInRect(p, o.rect));
    if (canvasRef.current) {
      if (isDraggingOverlay) canvasRef.current.style.cursor = 'grabbing';
      else if (overOverlay) canvasRef.current.style.cursor = 'pointer';
      else if (isDrawing) canvasRef.current.style.cursor = 'crosshair';
      else canvasRef.current.style.cursor = 'default';
    }

    if (isDrawing && startPoint) {
      const x = Math.min(p.x, startPoint.x);
      const y = Math.min(p.y, startPoint.y);
      const width = Math.abs(p.x - startPoint.x);
      const height = Math.abs(p.y - startPoint.y);
      setSelection({ x, y, width, height });
    } else if (isDraggingOverlay && selectedOverlayId && startPoint) {
      const dx = p.x - startPoint.x;
      const dy = p.y - startPoint.y;

      const newOverlays = slide.overlays.map(ov => {
        if (ov.id === selectedOverlayId) {
          return {
            ...ov,
            rect: { ...ov.rect, x: ov.rect.x + dx, y: ov.rect.y + dy }
          };
        }
        return ov;
      });

      onUpdateOverlays(newOverlays);
      setStartPoint(p);
    }
  };

  const handleMouseUp = () => {
    if (isDrawing) {
      if (selection && (selection.width < MIN_RECT_SIZE || selection.height < MIN_RECT_SIZE)) {
        setSelection(null);
        onSelectionChange(null);
      } else {
        onSelectionChange(selection);
      }
    }
    setIsDrawing(false);
    setIsDraggingOverlay(false);
    setStartPoint(null);
  };

  return (
    <div ref={containerRef} className="flex-1 relative overflow-hidden bg-[#0f172a] flex items-center justify-center select-none">
      <canvas ref={canvasRef} onMouseDown={handleMouseDown} onMouseMove={handleMouseMove} onMouseUp={handleMouseUp} onMouseLeave={handleMouseUp} className="block w-full h-full" />
      <div className="absolute top-4 left-1/2 -translate-x-1/2 bg-slate-800/90 px-5 py-2.5 rounded-full text-xs font-medium text-slate-200 border border-slate-700 shadow-2xl pointer-events-none flex items-center gap-5 backdrop-blur-sm">
        <div className="flex items-center gap-2">
          <span className="bg-slate-700 px-1.5 py-0.5 rounded text-[10px] text-blue-400 font-bold">Ctrl + Wheel</span>
          <span>확대/축소</span>
        </div>
        <div className="w-px h-3 bg-slate-600"></div>
        <div className="flex items-center gap-2">
          <span className="bg-slate-700 px-1.5 py-0.5 rounded text-[10px] text-blue-400 font-bold">Click & Drag</span>
          <span>텍스트 이동 / 영역 선택</span>
        </div>
      </div>
      <div className="absolute bottom-4 right-4 bg-slate-900/80 px-3 py-1.5 rounded-lg border border-slate-700 text-[10px] font-mono text-slate-400">
        ZOOM: {(zoom * 100).toFixed(0)}%
      </div>
    </div>
  );
};

export default EditorCanvas;

import React, { useState, useEffect } from 'react';
import { Rect, SlideData, TextOverlay, OCRResult } from '../types';
import { analyzeTextInImage } from '../services/geminiService';
import { Loader2, Type as TypeIcon, Info, CheckCircle2, Sliders, Palette, Bold } from 'lucide-react';

interface SidebarProps {
  activeSlide: SlideData | undefined;
  selection: Rect | null;
  selectedOverlayId: string | null;
  onApplyOverlay: (overlay: TextOverlay) => void;
  onUpdateOverlays: (overlays: TextOverlay[]) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
  activeSlide, 
  selection, 
  selectedOverlayId,
  onApplyOverlay,
  onUpdateOverlays
}) => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [ocrResult, setOcrResult] = useState<OCRResult | null>(null);

  // Controls state
  const [replacementText, setReplacementText] = useState('');
  const [fontSize, setFontSize] = useState(16);
  const [fontWeight, setFontWeight] = useState('normal');
  const [fontColor, setFontColor] = useState('#000000');

  const selectedOverlay = activeSlide?.overlays.find(o => o.id === selectedOverlayId);

  useEffect(() => {
    if (selection) {
      handleAnalyze();
    } else if (!selectedOverlayId) {
      setOcrResult(null);
      setReplacementText('');
    }
  }, [selection]);

  useEffect(() => {
    if (selectedOverlay) {
      setReplacementText(selectedOverlay.newText);
      setFontSize(selectedOverlay.fontSize);
      setFontWeight(selectedOverlay.fontWeight);
      setFontColor(selectedOverlay.fontColor);
    }
  }, [selectedOverlayId]);

  const handleAnalyze = async () => {
    if (!selection || !activeSlide) return;
    setIsAnalyzing(true);
    try {
      const canvas = document.createElement('canvas');
      canvas.width = selection.width;
      canvas.height = selection.height;
      const ctx = canvas.getContext('2d');
      const img = new Image();
      img.src = activeSlide.dataUrl;
      await new Promise(resolve => img.onload = resolve);
      ctx?.drawImage(img, selection.x, selection.y, selection.width, selection.height, 0, 0, selection.width, selection.height);
      const cropDataUrl = canvas.toDataURL('image/png');
      const result = await analyzeTextInImage(cropDataUrl);

      setOcrResult(result);
      setReplacementText(result.text);
      setFontSize(result.fontSize);
      setFontWeight(result.fontWeight);
      setFontColor(result.fontColor);
    } catch (err) {
      console.error(err);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const updateSelectedOverlay = (updates: Partial<TextOverlay>) => {
    if (!selectedOverlayId || !activeSlide) return;
    const newOverlays = activeSlide.overlays.map(ov => 
      ov.id === selectedOverlayId ? { ...ov, ...updates } : ov
    );
    onUpdateOverlays(newOverlays);
  };

  const handleApply = () => {
    if (!selection || !ocrResult) return;
    onApplyOverlay({
      id: Math.random().toString(36).substr(2, 9),
      rect: { ...selection },
      originalText: ocrResult.text,
      newText: replacementText,
      fontSize,
      fontWeight,
      fontColor,
      backgroundColor: ocrResult.backgroundColor
    });
  };

  const isEditing = !!selectedOverlayId;

  return (
    <div className="w-80 h-full bg-[#1e293b] border-l border-slate-700 flex flex-col p-6 overflow-y-auto">
      <div className="mb-6 flex items-center justify-between">
        <h2 className="text-sm font-bold text-slate-200 flex items-center gap-2">
          <TypeIcon size={16} className="text-blue-400" />
          {isEditing ? '텍스트 수정' : '텍스트 교체'}
        </h2>
        {isEditing && (
          <span className="text-[10px] bg-blue-600/20 text-blue-400 px-2 py-0.5 rounded font-bold border border-blue-500/30 uppercase tracking-tighter">Selected</span>
        )}
      </div>

      {!selection && !isEditing ? (
        <div className="flex-1 flex flex-col items-center justify-center text-center text-slate-400">
          <div className="w-16 h-16 rounded-xl bg-slate-800 flex items-center justify-center mb-4 border border-slate-700 shadow-inner">
            <Info size={32} className="opacity-50" />
          </div>
          <p className="text-sm">텍스트를 교체할<br/>영역을 선택하거나<br/>교체된 텍스트를 클릭하세요</p>
        </div>
      ) : (
        <div className="space-y-6">
          {!isEditing && (
            <div className="bg-slate-800/50 rounded-xl p-4 border border-slate-700">
              <h3 className="text-xs font-medium text-slate-400 uppercase tracking-wider mb-3">분석 결과 (OCR)</h3>
              {isAnalyzing ? (
                <div className="flex items-center gap-3 py-4 text-blue-400">
                  <Loader2 className="animate-spin" size={18} />
                  <span className="text-sm">AI가 분석 중입니다...</span>
                </div>
              ) : ocrResult ? (
                <div className="space-y-3">
                  <div className="p-3 bg-slate-900 rounded text-sm text-slate-300 italic border border-slate-800">"{ocrResult.text}"</div>
                </div>
              ) : null}
            </div>
          )}

          <div className="space-y-4">
            <div className="space-y-2">
              <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest">내용</label>
              <textarea 
                value={replacementText} 
                onChange={(e) => {
                  setReplacementText(e.target.value);
                  if (isEditing) updateSelectedOverlay({ newText: e.target.value });
                }} 
                className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-sm h-28 resize-none focus:outline-none focus:border-blue-500 transition-colors shadow-inner text-slate-200" 
                placeholder="텍스트 입력..." 
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="flex items-center gap-1.5 text-[10px] font-bold text-slate-500 uppercase tracking-widest">
                  <Sliders size={12} /> 크기
                </label>
                <input 
                  type="number" 
                  value={fontSize} 
                  onChange={(e) => {
                    const val = parseInt(e.target.value);
                    setFontSize(val);
                    if (isEditing) updateSelectedOverlay({ fontSize: val });
                  }}
                  className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-sm focus:outline-none focus:border-blue-500" 
                />
              </div>
              <div className="space-y-2">
                <label className="flex items-center gap-1.5 text-[10px] font-bold text-slate-500 uppercase tracking-widest">
                  <Palette size={12} /> 색상
                </label>
                <div className="flex gap-2 items-center bg-slate-900 border border-slate-700 rounded-lg px-2 py-1">
                  <input 
                    type="color" 
                    value={fontColor} 
                    onChange={(e) => {
                      setFontColor(e.target.value);
                      if (isEditing) updateSelectedOverlay({ fontColor: e.target.value });
                    }}
                    className="w-8 h-8 bg-transparent border-none cursor-pointer"
                  />
                  <span className="text-[10px] font-mono text-slate-400 uppercase">{fontColor}</span>
                </div>
              </div>
            </div>

            <div className="space-y-2">
              <label className="flex items-center gap-1.5 text-[10px] font-bold text-slate-500 uppercase tracking-widest">
                <Bold size={12} /> 스타일
              </label>
              <div className="flex p-1 bg-slate-900 rounded-lg border border-slate-800">
                <button 
                  onClick={() => {
                    setFontWeight('normal');
                    if (isEditing) updateSelectedOverlay({ fontWeight: 'normal' });
                  }}
                  className={`flex-1 py-1.5 text-xs font-medium rounded transition-all ${fontWeight === 'normal' ? 'bg-slate-700 text-white shadow-sm' : 'text-slate-500 hover:text-slate-300'}`}
                >
                  Normal
                </button>
                <button 
                  onClick={() => {
                    setFontWeight('bold');
                    if (isEditing) updateSelectedOverlay({ fontWeight: 'bold' });
                  }}
                  className={`flex-1 py-1.5 text-xs font-bold rounded transition-all ${fontWeight === 'bold' ? 'bg-slate-700 text-white shadow-sm' : 'text-slate-500 hover:text-slate-300'}`}
                >
                  Bold
                </button>
              </div>
            </div>

            {!isEditing && (
              <button 
                onClick={handleApply} 
                disabled={isAnalyzing || !ocrResult} 
                className="w-full bg-blue-600 hover:bg-blue-500 disabled:opacity-50 text-white font-bold py-3.5 rounded-lg flex items-center justify-center gap-2 transition-all shadow-lg shadow-blue-900/20 mt-4 active:scale-95"
              >
                <CheckCircle2 size={18} /> 텍스트 적용
              </button>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default Sidebar;

import React, { useState, useEffect } from 'react';
import { SlideData, Rect, TextOverlay } from './types';
import { convertPdfToImages, downloadAsPdf } from './services/pdfService';
import EditorCanvas from './components/EditorCanvas';
import Sidebar from './components/Sidebar';
import { 
  FileUp, 
  Download, 
  FileText, 
  ChevronLeft, 
  ChevronRight, 
  Trash2, 
  History
} from 'lucide-react';

const App: React.FC = () => {
  const [slides, setSlides] = useState<SlideData[]>([]);
  const [activeSlideIdx, setActiveSlideIdx] = useState(0);
  const [selection, setSelection] = useState<Rect | null>(null);
  const [selectedOverlayId, setSelectedOverlayId] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessing(true);
    try {
      const converted = await convertPdfToImages(file);
      setSlides(converted);
      setActiveSlideIdx(0);
      setSelectedOverlayId(null);
    } catch (err) {
      console.error(err);
      alert('PDF 변환 중 오류가 발생했습니다.');
    } finally {
      setIsProcessing(false);
    }
  };

  const handleApplyOverlay = (overlay: TextOverlay) => {
    setSlides(prev => prev.map((s, idx) => idx === activeSlideIdx ? { ...s, overlays: [...s.overlays, overlay] } : s));
    setSelection(null);
    setSelectedOverlayId(overlay.id);
  };

  const handleUpdateOverlays = (overlays: TextOverlay[]) => {
    setSlides(prev => prev.map((s, idx) => idx === activeSlideIdx ? { ...s, overlays } : s));
  };

  const handleUndo = () => {
    setSlides(prev => prev.map((s, idx) => {
      if (idx === activeSlideIdx && s.overlays.length > 0) {
        const newOverlays = [...s.overlays];
        newOverlays.pop();
        return { ...s, overlays: newOverlays };
      }
      return s;
    }));
    setSelectedOverlayId(null);
  };

  const handleDownloadImages = () => {
    slides.forEach((slide, i) => {
      const canvas = document.createElement('canvas');
      canvas.width = slide.width;
      canvas.height = slide.height;
      const ctx = canvas.getContext('2d')!;
      const img = new Image();
      img.src = slide.dataUrl;
      img.onload = () => {
        ctx.drawImage(img, 0, 0);

        // Render Overlays
        slide.overlays.forEach(ov => {
          ctx.fillStyle = ov.backgroundColor;
